{
  "name": "Concert Planner Pro",
  "description": "A comprehensive concert travel planning tool to track flights, hotels, costs, and performance details with beautiful Excel export and cross-device support."
}

export interface ConcertPlan {
  id: string;
  artist: string;
  city: string;
  sessions: string;
  departureFlight1: string;
  departureFlight2: string;
  returnFlight1: string;
  returnFlight2: string;
  hotel1: string;
  hotel2: string;
  flightCost: number;
  hotelCost: number;
  status: 'Planning' | 'Booked' | 'Completed';
  createdAt: number;
}

export type SortField = 'artist' | 'city' | 'flightCost' | 'hotelCost' | 'totalCost' | 'createdAt';
export type SortOrder = 'asc' | 'desc';

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

import React, { useState, useEffect, useMemo } from 'react';
import { Plus, Download, Search, Filter, Trash2, Edit2, Plane, Hotel, MapPin, Calendar, CreditCard, ChevronDown, CheckCircle2, Circle } from 'lucide-react';
import { ConcertPlan, SortField, SortOrder } from './types';
import ConcertForm from './components/ConcertForm';
import { exportToExcel } from './services/exportService';

const App: React.FC = () => {
  const [plans, setPlans] = useState<ConcertPlan[]>(() => {
    const saved = localStorage.getItem('concert_plans');
    return saved ? JSON.parse(saved) : [];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPlan, setEditingPlan] = useState<ConcertPlan | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [filterStatus, setFilterStatus] = useState<string>('All');
  const [sortField, setSortField] = useState<SortField>('createdAt');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');

  useEffect(() => {
    localStorage.setItem('concert_plans', JSON.stringify(plans));
  }, [plans]);

  const filteredAndSortedPlans = useMemo(() => {
    return plans
      .filter(plan => {
        const matchesSearch = 
          plan.artist.toLowerCase().includes(searchTerm.toLowerCase()) ||
          plan.city.toLowerCase().includes(searchTerm.toLowerCase());
        const matchesStatus = filterStatus === 'All' || plan.status === filterStatus;
        return matchesSearch && matchesStatus;
      })
      .sort((a, b) => {
        let valA: any = a[sortField as keyof ConcertPlan];
        let valB: any = b[sortField as keyof ConcertPlan];

        // Special case for calculated total cost if needed
        if (sortField === 'totalCost' as any) {
          valA = a.flightCost + a.hotelCost;
          valB = b.flightCost + b.hotelCost;
        }

        if (valA < valB) return sortOrder === 'asc' ? -1 : 1;
        if (valA > valB) return sortOrder === 'asc' ? 1 : -1;
        return 0;
      });
  }, [plans, searchTerm, filterStatus, sortField, sortOrder]);

  const handleAddPlan = (newPlan: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    const plan: ConcertPlan = {
      ...newPlan,
      id: crypto.randomUUID(),
      createdAt: Date.now(),
    };
    setPlans(prev => [plan, ...prev]);
    setIsModalOpen(false);
  };

  const handleUpdatePlan = (updatedData: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    if (!editingPlan) return;
    setPlans(prev => prev.map(p => p.id === editingPlan.id ? { ...p, ...updatedData } : p));
    setEditingPlan(null);
    setIsModalOpen(false);
  };

  const handleDeletePlan = (id: string) => {
    if (confirm('确定要删除这个计划吗？')) {
      setPlans(prev => prev.filter(p => p.id !== id));
    }
  };

  const openEditModal = (plan: ConcertPlan) => {
    setEditingPlan(plan);
    setIsModalOpen(true);
  };

  return (
    <div className="min-h-screen pb-20 md:pb-8">
      {/* Header */}
      <header className="bg-white border-b sticky top-0 z-30 px-4 py-4 md:px-8 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl text-white">
              <Calendar className="w-6 h-6" />
            </div>
            <h1 className="text-xl md:text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600">
              Concert Planner Pro
            </h1>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => exportToExcel(plans)}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-emerald-50 text-emerald-700 px-4 py-2 rounded-lg border border-emerald-200 hover:bg-emerald-100 transition-all font-medium"
            >
              <Download className="w-4 h-4" />
              <span>导出 Excel</span>
            </button>
            <button 
              onClick={() => { setEditingPlan(null); setIsModalOpen(true); }}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition-all shadow-md hover:shadow-lg font-medium"
            >
              <Plus className="w-4 h-4" />
              <span>新计划</span>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6 md:px-8">
        {/* Filters */}
        <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm mb-6 flex flex-col md:flex-row gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder="搜索艺人、城市..."
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex gap-2">
            <select 
              className="px-4 py-2 border border-slate-200 rounded-lg outline-none bg-white cursor-pointer"
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
            >
              <option value="All">所有状态</option>
              <option value="Planning">计划中</option>
              <option value="Booked">已预订</option>
              <option value="Completed">已完成</option>
            </select>
            <div className="relative group">
               <select 
                className="px-4 py-2 border border-slate-200 rounded-lg outline-none bg-white cursor-pointer appearance-none pr-8"
                value={sortField}
                onChange={(e) => setSortField(e.target.value as SortField)}
              >
                <option value="createdAt">按时间</option>
                <option value="artist">按艺人</option>
                <option value="city">按城市</option>
                <option value="flightCost">按机票费</option>
                <option value="hotelCost">按酒店费</option>
              </select>
              <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            </div>
          </div>
        </div>

        {/* Content List - Desktop Table */}
        <div className="hidden md:block overflow-hidden bg-white border border-slate-200 rounded-xl shadow-sm">
          <table className="w-full text-left border-collapse">
            <thead className="bg-slate-50 border-b border-slate-200">
              <tr>
                <th className="px-6 py-4 font-semibold text-slate-600">艺人/场次</th>
                <th className="px-6 py-4 font-semibold text-slate-600">城市</th>
                <th className="px-6 py-4 font-semibold text-slate-600">航班信息</th>
                <th className="px-6 py-4 font-semibold text-slate-600">酒店信息</th>
                <th className="px-6 py-4 font-semibold text-slate-600">费用估计</th>
                <th className="px-6 py-4 font-semibold text-slate-600">状态</th>
                <th className="px-6 py-4 font-semibold text-slate-600">操作</th>
              </tr>
            </thead>
            <tbody className="divide-y divide-slate-200">
              {filteredAndSortedPlans.map(plan => (
                <tr key={plan.id} className="hover:bg-slate-50 transition-colors">
                  <td className="px-6 py-4">
                    <div className="font-bold text-slate-900">{plan.artist}</div>
                    <div className="text-sm text-slate-500">{plan.sessions}</div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-1.5 text-slate-700 font-medium">
                      <MapPin className="w-4 h-4 text-indigo-500" />
                      {plan.city}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="space-y-1">
                      {plan.departureFlight1 && <div className="text-xs bg-blue-50 text-blue-700 px-2 py-0.5 rounded flex items-center gap-1"><Plane className="w-3 h-3 rotate-45" /> {plan.departureFlight1}</div>}
                      {plan.returnFlight1 && <div className="text-xs bg-indigo-50 text-indigo-700 px-2 py-0.5 rounded flex items-center gap-1"><Plane className="w-3 h-3 -rotate-45" /> {plan.returnFlight1}</div>}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-xs text-slate-600 flex items-center gap-1">
                      <Hotel className="w-3 h-3" /> {plan.hotel1 || '未填写'}
                    </div>
                  </td>
                  <td className="px-6 py-4">
                    <div className="text-sm font-semibold text-slate-900">¥{(plan.flightCost + plan.hotelCost).toLocaleString()}</div>
                    <div className="text-[10px] text-slate-400">机: {plan.flightCost} / 酒: {plan.hotelCost}</div>
                  </td>
                  <td className="px-6 py-4">
                    <StatusBadge status={plan.status} />
                  </td>
                  <td className="px-6 py-4">
                    <div className="flex items-center gap-2">
                      <button onClick={() => openEditModal(plan)} className="p-2 text-slate-400 hover:text-indigo-600 transition-colors">
                        <Edit2 className="w-4 h-4" />
                      </button>
                      <button onClick={() => handleDeletePlan(plan.id)} className="p-2 text-slate-400 hover:text-red-600 transition-colors">
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  </td>
                </tr>
              ))}
              {filteredAndSortedPlans.length === 0 && (
                <tr>
                  <td colSpan={7} className="px-6 py-12 text-center text-slate-400">
                    暂无演唱会计划，快去添加一个吧！
                  </td>
                </tr>
              )}
            </tbody>
          </table>
        </div>

        {/* Content List - Mobile Cards */}
        <div className="md:hidden space-y-4">
          {filteredAndSortedPlans.map(plan => (
            <div key={plan.id} className="bg-white rounded-2xl border border-slate-200 p-4 shadow-sm active:scale-[0.98] transition-transform">
              <div className="flex justify-between items-start mb-3">
                <div>
                  <h3 className="text-lg font-bold text-slate-900">{plan.artist}</h3>
                  <div className="text-sm text-slate-500 flex items-center gap-1">
                    <MapPin className="w-3 h-3" /> {plan.city} · {plan.sessions}
                  </div>
                </div>
                <StatusBadge status={plan.status} />
              </div>

              <div className="grid grid-cols-2 gap-3 mb-4">
                <div className="bg-slate-50 p-2 rounded-xl">
                  <div className="text-[10px] uppercase text-slate-400 font-bold mb-1 flex items-center gap-1">
                    <Plane className="w-3 h-3" /> 航班
                  </div>
                  <div className="text-xs text-slate-700 truncate">{plan.departureFlight1 || '无'}</div>
                  <div className="text-xs text-slate-700 truncate">{plan.returnFlight1 || '无'}</div>
                </div>
                <div className="bg-slate-50 p-2 rounded-xl">
                  <div className="text-[10px] uppercase text-slate-400 font-bold mb-1 flex items-center gap-1">
                    <Hotel className="w-3 h-3" /> 酒店
                  </div>
                  <div className="text-xs text-slate-700 truncate">{plan.hotel1 || '无'}</div>
                  <div className="text-[10px] text-slate-400">¥{plan.hotelCost}</div>
                </div>
              </div>

              <div className="flex items-center justify-between pt-3 border-t border-slate-100">
                <div className="flex items-center gap-1 text-indigo-600">
                  <CreditCard className="w-4 h-4" />
                  <span className="font-bold">¥{(plan.flightCost + plan.hotelCost).toLocaleString()}</span>
                </div>
                <div className="flex gap-1">
                  <button onClick={() => openEditModal(plan)} className="p-2 text-slate-500 bg-slate-100 rounded-lg">
                    <Edit2 className="w-4 h-4" />
                  </button>
                  <button onClick={() => handleDeletePlan(plan.id)} className="p-2 text-red-500 bg-red-50 rounded-lg">
                    <Trash2 className="w-4 h-4" />
                  </button>
                </div>
              </div>
            </div>
          ))}
          {filteredAndSortedPlans.length === 0 && (
            <div className="text-center py-12 text-slate-400">
              暂无匹配的计划
            </div>
          )}
        </div>
      </main>

      {/* Mobile Add FAB */}
      <button 
        onClick={() => { setEditingPlan(null); setIsModalOpen(true); }}
        className="md:hidden fixed bottom-6 right-6 w-14 h-14 bg-indigo-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-40"
      >
        <Plus className="w-8 h-8" />
      </button>

      {/* Modal */}
      {isModalOpen && (
        <ConcertForm 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={editingPlan ? handleUpdatePlan : handleAddPlan}
          initialData={editingPlan}
        />
      )}
    </div>
  );
};

const StatusBadge: React.FC<{ status: string }> = ({ status }) => {
  const styles = {
    Planning: "bg-amber-50 text-amber-700 border-amber-200",
    Booked: "bg-blue-50 text-blue-700 border-blue-200",
    Completed: "bg-emerald-50 text-emerald-700 border-emerald-200",
  }[status] || "bg-slate-50 text-slate-700 border-slate-200";

  return (
    <span className={`px-2 py-1 rounded-full text-xs font-bold border ${styles} flex items-center gap-1 w-fit`}>
      {status === 'Completed' ? <CheckCircle2 className="w-3 h-3" /> : <Circle className="w-3 h-3" />}
      {status === 'Planning' ? '计划中' : status === 'Booked' ? '已预订' : '已完成'}
    </span>
  );
};

export default App;

import { ConcertPlan } from '../types';

export const exportToExcel = (plans: ConcertPlan[]) => {
  if (plans.length === 0) {
    alert('没有数据可导出');
    return;
  }

  // Define column headers mapping
  const excelData = plans.map(plan => ({
    '艺人': plan.artist,
    '城市': plan.city,
    '演出场次': plan.sessions,
    '去程航班1': plan.departureFlight1,
    '去程航班2': plan.departureFlight2,
    '返程航班1': plan.returnFlight1,
    '返程航班2': plan.returnFlight2,
    '酒店1': plan.hotel1,
    '酒店2': plan.hotel2,
    '机票合计金额': plan.flightCost,
    '酒店合计金额': plan.hotelCost,
    '总计金额': plan.flightCost + plan.hotelCost,
    '状态': plan.status === 'Planning' ? '计划中' : plan.status === 'Booked' ? '已预订' : '已完成',
    '创建时间': new Date(plan.createdAt).toLocaleString()
  }));

  // Create a new workbook
  const wb = (window as any).XLSX.utils.book_new();
  const ws = (window as any).XLSX.utils.json_to_sheet(excelData);

  // Auto-size columns (rough approximation)
  const colWidths = Object.keys(excelData[0]).map(key => ({
    wch: Math.max(key.length * 2, 12)
  }));
  ws['!cols'] = colWidths;

  // Append sheet to workbook
  (window as any).XLSX.utils.book_append_sheet(wb, ws, "演唱会计划表");

  // Generate file name
  const fileName = `Concert_Plan_${new Date().toISOString().slice(0, 10)}.xlsx`;

  // Save the file
  (window as any).XLSX.writeFile(wb, fileName);
};

export type BookingStatus = 'Pending' | 'Booked';

export interface ConcertPlan {
  id: string;
  concertName: string;
  city: string;
  sessions: string;
  // Ticket Info
  ticketDate: string; // YYYY-MM-DD
  ticketSeat: string;
  ticketPrice: number;
  ticketStatus: BookingStatus;
  // Flight Info
  departureFlight1: string;
  departureFlight2: string;
  returnFlight1: string;
  returnFlight2: string;
  flightCost: number;
  flightStatus: BookingStatus;
  // Hotel Info
  hotel1: string;
  hotel2: string;
  hotelCost: number;
  hotelStatus: BookingStatus;

  createdAt: number;
}

export type SortField = 'concertName' | 'city' | 'ticketPrice' | 'flightCost' | 'hotelCost' | 'totalCost' | 'createdAt' | 'ticketDate';
export type SortOrder = 'asc' | 'desc';

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plus, Download, Search, Trash2, Edit2, Plane, Hotel, MapPin, 
  Calendar, CreditCard, ChevronDown, Ticket, CheckCircle2, 
  Circle, X, ChevronRight, Info, ExternalLink
} from 'lucide-react';
import { ConcertPlan, SortField, SortOrder } from './types';
import ConcertForm from './components/ConcertForm';
import { exportToExcel } from './services/exportService';

const App: React.FC = () => {
  const [plans, setPlans] = useState<ConcertPlan[]>(() => {
    const saved = localStorage.getItem('concert_plans_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPlan, setEditingPlan] = useState<ConcertPlan | null>(null);
  const [viewingPlan, setViewingPlan] = useState<ConcertPlan | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortField, setSortField] = useState<SortField>('ticketDate');
  const [sortOrder, setSortOrder] = useState<SortOrder>('asc');

  useEffect(() => {
    localStorage.setItem('concert_plans_v2', JSON.stringify(plans));
  }, [plans]);

  const filteredAndSortedPlans = useMemo(() => {
    return plans
      .filter(plan => {
        const matchesSearch = 
          plan.concertName.toLowerCase().includes(searchTerm.toLowerCase()) ||
          plan.city.toLowerCase().includes(searchTerm.toLowerCase());
        return matchesSearch;
      })
      .sort((a, b) => {
        let valA: any = a[sortField as keyof ConcertPlan];
        let valB: any = b[sortField as keyof ConcertPlan];

        if (sortField === 'totalCost' as any) {
          valA = a.flightCost + a.hotelCost + a.ticketPrice;
          valB = b.flightCost + b.hotelCost + b.ticketPrice;
        }

        if (valA < valB) return sortOrder === 'asc' ? -1 : 1;
        if (valA > valB) return sortOrder === 'asc' ? 1 : -1;
        return 0;
      });
  }, [plans, searchTerm, sortField, sortOrder]);

  const handleAddPlan = (newPlan: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    const plan: ConcertPlan = {
      ...newPlan,
      id: crypto.randomUUID(),
      createdAt: Date.now(),
    };
    setPlans(prev => [plan, ...prev]);
    setIsModalOpen(false);
  };

  const handleUpdatePlan = (updatedData: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    if (!editingPlan) return;
    setPlans(prev => prev.map(p => p.id === editingPlan.id ? { ...p, ...updatedData } : p));
    setEditingPlan(null);
    setIsModalOpen(false);
  };

  const handleDeletePlan = (id: string) => {
    if (confirm('确定要删除这个计划吗？')) {
      setPlans(prev => prev.filter(p => p.id !== id));
      if (viewingPlan?.id === id) setViewingPlan(null);
    }
  };

  const openEditModal = (e: React.MouseEvent, plan: ConcertPlan) => {
    e.stopPropagation();
    setEditingPlan(plan);
    setIsModalOpen(true);
  };

  const getDayOfWeek = (dateStr: string) => {
    if (!dateStr) return '';
    const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    const date = new Date(dateStr);
    return days[date.getDay()];
  };

  return (
    <div className="min-h-screen pb-20 md:pb-8 bg-slate-50">
      <header className="bg-white border-b sticky top-0 z-30 px-4 py-4 md:px-8 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl text-white">
              <Calendar className="w-6 h-6" />
            </div>
            <h1 className="text-xl md:text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600">
              Concert Planner Pro
            </h1>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => exportToExcel(plans)}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-emerald-50 text-emerald-700 px-4 py-2 rounded-lg border border-emerald-200 hover:bg-emerald-100 transition-all font-medium text-sm"
            >
              <Download className="w-4 h-4" />
              <span>导出 Excel</span>
            </button>
            <button 
              onClick={() => { setEditingPlan(null); setIsModalOpen(true); }}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition-all shadow-md hover:shadow-lg font-medium text-sm"
            >
              <Plus className="w-4 h-4" />
              <span>新计划</span>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6 md:px-8">
        <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm mb-6 flex flex-col md:flex-row gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder="搜索演唱会、城市..."
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex gap-2">
            <div className="relative group flex-1 md:flex-none">
               <select 
                className="w-full px-4 py-2 border border-slate-200 rounded-lg outline-none bg-white cursor-pointer appearance-none pr-8 text-sm"
                value={sortField}
                onChange={(e) => setSortField(e.target.value as SortField)}
              >
                <option value="ticketDate">按演出日期</option>
                <option value="concertName">按演出名称</option>
                <option value="city">按城市</option>
                <option value="totalCost">按总费用</option>
              </select>
              <ChevronDown className="absolute right-2 top-1/2 -translate-y-1/2 w-4 h-4 text-slate-400 pointer-events-none" />
            </div>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
          {filteredAndSortedPlans.map(plan => (
            <div 
              key={plan.id} 
              onClick={() => setViewingPlan(plan)}
              className="bg-white rounded-2xl border border-slate-200 p-5 shadow-sm hover:shadow-md hover:border-indigo-200 transition-all cursor-pointer group"
