                  <div className="flex items-center gap-2 mt-1 text-slate-500 text-sm">
                    <MapPin className="w-3.5 h-3.5 text-indigo-500" />
                    <span>{plan.city}</span>
                    <span className="text-slate-300">|</span>
                    <Calendar className="w-3.5 h-3.5 text-indigo-500" />
                    <span>{plan.ticketDate} ({getDayOfWeek(plan.ticketDate)})</span>
                  </div>
                </div>
                <div className="flex gap-1.5 ml-2">
                   <StatusIcon type="ticket" status={plan.ticketStatus} />
                   <StatusIcon type="flight" status={plan.flightStatus} />
                   <StatusIcon type="hotel" status={plan.hotelStatus} />
                </div>
              </div>

              <div className="space-y-3">
                <div className="flex items-center justify-between p-3 bg-slate-50 rounded-xl">
                  <div className="text-xs font-bold text-slate-400 uppercase tracking-tight">演出场次 / 位置</div>
                  <div className="text-sm font-medium text-slate-700">{plan.sessions} / {plan.ticketSeat || '-'}</div>
                </div>

                <div className="flex items-center justify-between text-indigo-600 font-bold px-1">
                   <div className="flex items-center gap-1.5">
                     <CreditCard className="w-4 h-4" />
                     <span>¥{(plan.flightCost + plan.hotelCost + plan.ticketPrice).toLocaleString()}</span>
                   </div>
                   <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-opacity">
                      <button onClick={(e) => openEditModal(e, plan)} className="p-1.5 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-lg">
                        <Edit2 className="w-4 h-4" />
                      </button>
                   </div>
                </div>
              </div>
            </div>
          ))}
        </div>

        {filteredAndSortedPlans.length === 0 && (
          <div className="text-center py-24 bg-white rounded-3xl border-2 border-dashed border-slate-200">
            <div className="bg-slate-50 w-16 h-16 rounded-full flex items-center justify-center mx-auto mb-4 text-slate-300">
              <Search className="w-8 h-8" />
            </div>
            <p className="text-slate-400 font-medium">没找到相关的演唱会计划</p>
            <button onClick={() => setIsModalOpen(true)} className="mt-4 text-indigo-600 font-bold hover:underline">
              现在去创建一个？
            </button>
          </div>
        )}
      </main>

      {/* Floating Action Button */}
      <button 
        onClick={() => { setEditingPlan(null); setIsModalOpen(true); }}
        className="fixed bottom-8 right-8 w-14 h-14 bg-indigo-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-40"
      >
        <Plus className="w-8 h-8" />
      </button>

      {/* Detail View Drawer */}
      {viewingPlan && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setViewingPlan(null)} />
          <div className="relative w-full max-w-lg bg-slate-50 h-full shadow-2xl overflow-y-auto animate-in slide-in-from-right duration-300">
            <div className="sticky top-0 bg-white px-6 py-4 border-b flex justify-between items-center z-10">
              <h2 className="text-xl font-black text-slate-900">计划详情</h2>
              <div className="flex items-center gap-2">
                <button onClick={(e) => openEditModal(e, viewingPlan)} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-lg"><Edit2 className="w-5 h-5" /></button>
                <button onClick={() => handleDeletePlan(viewingPlan.id)} className="p-2 text-red-500 hover:bg-red-50 rounded-lg"><Trash2 className="w-5 h-5" /></button>
                <button onClick={() => setViewingPlan(null)} className="p-2 text-slate-400 hover:text-slate-900 ml-2"><X className="w-6 h-6" /></button>
              </div>
            </div>

            <div className="p-6 space-y-6">
              {/* Header Card */}
              <div className="bg-gradient-to-br from-indigo-600 to-purple-700 rounded-3xl p-6 text-white shadow-xl relative overflow-hidden">
                <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -mr-16 -mt-16 blur-2xl" />
                <div className="relative z-10">
                  <div className="text-indigo-100 text-xs font-black uppercase tracking-widest mb-1 flex items-center gap-2">
                    <MusicNote className="w-3 h-3" /> CONCERT JOURNEY
                  </div>
                  <h3 className="text-3xl font-black leading-tight mb-2">{viewingPlan.concertName}</h3>
                  <div className="flex items-center gap-4 text-sm font-medium text-indigo-100">
                    <div className="flex items-center gap-1.5"><MapPin className="w-4 h-4" /> {viewingPlan.city}</div>
                    <div className="flex items-center gap-1.5"><Calendar className="w-4 h-4" /> {viewingPlan.ticketDate} ({getDayOfWeek(viewingPlan.ticketDate)})</div>
                  </div>
                </div>
              </div>

              {/* Status & Summary */}
              <div className="grid grid-cols-3 gap-3">
                 <SummaryCard label="门票" status={viewingPlan.ticketStatus} icon={<Ticket className="w-4 h-4" />} color="amber" />
                 <SummaryCard label="航班" status={viewingPlan.flightStatus} icon={<Plane className="w-4 h-4" />} color="blue" />
                 <SummaryCard label="酒店" status={viewingPlan.hotelStatus} icon={<Hotel className="w-4 h-4" />} color="emerald" />
              </div>

              {/* Detailed Sections */}
              <div className="space-y-4">
                <DetailSection title="门票信息" icon={<Ticket className="w-5 h-5" />}>
                   <div className="grid grid-cols-2 gap-4">
                     <InfoItem label="场次" value={viewingPlan.sessions} />
                     <InfoItem label="位置" value={viewingPlan.ticketSeat} />
                     <InfoItem label="价格" value={`¥${viewingPlan.ticketPrice}`} isPrice />
                   </div>
                </DetailSection>

                <DetailSection title="交通安排" icon={<Plane className="w-5 h-5" />}>
                   <div className="space-y-3">
                     <div className="flex items-start gap-3">
                       <div className="bg-blue-100 p-2 rounded-lg text-blue-600 mt-1"><ChevronRight className="w-4 h-4 rotate-45" /></div>
                       <div>
                         <div className="text-xs font-bold text-slate-400">去程</div>
                         <div className="text-sm font-medium text-slate-700">{viewingPlan.departureFlight1 || '未填写'}</div>
                         {viewingPlan.departureFlight2 && <div className="text-xs text-slate-500 mt-0.5">{viewingPlan.departureFlight2}</div>}
                       </div>
                     </div>
                     <div className="flex items-start gap-3">
                       <div className="bg-indigo-100 p-2 rounded-lg text-indigo-600 mt-1"><ChevronRight className="w-4 h-4 -rotate-45" /></div>
                       <div>
                         <div className="text-xs font-bold text-slate-400">返程</div>
                         <div className="text-sm font-medium text-slate-700">{viewingPlan.returnFlight1 || '未填写'}</div>
                         {viewingPlan.returnFlight2 && <div className="text-xs text-slate-500 mt-0.5">{viewingPlan.returnFlight2}</div>}
                       </div>
                     </div>
                     <div className="pt-2 mt-2 border-t border-slate-100">
                        <InfoItem label="机票支出" value={`¥${viewingPlan.flightCost}`} isPrice />
                     </div>
                   </div>
                </DetailSection>

                <DetailSection title="住宿计划" icon={<Hotel className="w-5 h-5" />}>
                   <div className="space-y-3">
                      <div className="flex items-start gap-3">
                         <div className="bg-emerald-100 p-2 rounded-lg text-emerald-600 mt-1"><Hotel className="w-4 h-4" /></div>
                         <div>
                            <div className="text-xs font-bold text-slate-400">酒店 1</div>
                            <div className="text-sm font-medium text-slate-700">{viewingPlan.hotel1 || '未填写'}</div>
                         </div>
                      </div>
                      {viewingPlan.hotel2 && (
                         <div className="flex items-start gap-3">
                            <div className="bg-emerald-50 p-2 rounded-lg text-emerald-500 mt-1"><Hotel className="w-4 h-4" /></div>
                            <div>
                               <div className="text-xs font-bold text-slate-400">酒店 2</div>
                               <div className="text-sm font-medium text-slate-700">{viewingPlan.hotel2}</div>
                            </div>
                         </div>
                      )}
                      <div className="pt-2 mt-2 border-t border-slate-100">
                        <InfoItem label="酒店支出" value={`¥${viewingPlan.hotelCost}`} isPrice />
                     </div>
                   </div>
                </DetailSection>
              </div>

              {/* Total Footer */}
              <div className="bg-white rounded-3xl p-6 border border-slate-200 shadow-inner flex items-center justify-between">
                <div className="text-slate-400 font-bold uppercase tracking-widest text-sm">TOTAL COST</div>
                <div className="text-3xl font-black text-indigo-600">¥{(viewingPlan.ticketPrice + viewingPlan.flightCost + viewingPlan.hotelCost).toLocaleString()}</div>
              </div>
            </div>
          </div>
        </div>
      )}

      {/* Form Modal */}
      {isModalOpen && (
        <ConcertForm 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={editingPlan ? handleUpdatePlan : handleAddPlan}
          initialData={editingPlan}
        />
      )}
    </div>
  );
};

const StatusIcon: React.FC<{ type: 'ticket' | 'flight' | 'hotel', status: string }> = ({ type, status }) => {
  const Icon = type === 'ticket' ? Ticket : type === 'flight' ? Plane : Hotel;
  const isBooked = status === 'Booked';
  const colorClass = type === 'ticket' ? 'amber' : type === 'flight' ? 'blue' : 'emerald';

  return (
    <div className={`p-1.5 rounded-lg border transition-all ${isBooked ? `bg-${colorClass}-50 text-${colorClass}-600 border-${colorClass}-200 shadow-sm` : 'bg-slate-50 text-slate-300 border-slate-100'}`}>
      <Icon className="w-3.5 h-3.5" />
    </div>
  );
};

const SummaryCard: React.FC<{ label: string, status: string, icon: React.ReactNode, color: string }> = ({ label, status, icon, color }) => {
  const isBooked = status === 'Booked';
  const colorMap: Record<string, string> = {
    amber: isBooked ? 'bg-amber-100 text-amber-700 border-amber-200' : 'bg-slate-100 text-slate-400 border-slate-200',
    blue: isBooked ? 'bg-blue-100 text-blue-700 border-blue-200' : 'bg-slate-100 text-slate-400 border-slate-200',
    emerald: isBooked ? 'bg-emerald-100 text-emerald-700 border-emerald-200' : 'bg-slate-100 text-slate-400 border-slate-200',
  };

  return (
    <div className={`rounded-2xl p-3 border text-center transition-all ${colorMap[color]}`}>
      <div className="flex justify-center mb-1">{icon}</div>
      <div className="text-[10px] font-black uppercase tracking-widest opacity-60 mb-1">{label}</div>
      <div className="text-xs font-bold">{isBooked ? '已预订' : '待处理'}</div>
    </div>
  );
};

const DetailSection: React.FC<{ title: string, icon: React.ReactNode, children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="bg-white rounded-2xl border border-slate-200 overflow-hidden shadow-sm">
    <div className="px-4 py-3 bg-slate-50 border-b flex items-center gap-2 font-bold text-slate-700">
       <span className="text-indigo-500">{icon}</span>
       <span>{title}</span>
    </div>
    <div className="p-4">
      {children}
    </div>
  </div>
);

const InfoItem: React.FC<{ label: string, value: string | number, isPrice?: boolean }> = ({ label, value, isPrice }) => (
  <div>
    <div className="text-[10px] font-black uppercase tracking-widest text-slate-400 mb-0.5">{label}</div>
    <div className={`text-sm font-bold ${isPrice ? 'text-indigo-600' : 'text-slate-800'}`}>{value || '-'}</div>
  </div>
);

const MusicNote = ({ className }: { className?: string }) => (
  <svg className={className} viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M9 18V5l12-2v13"/><circle cx="6" cy="18" r="3"/><circle cx="18" cy="16" r="3"/></svg>
);

export default App;

import React, { useState, useEffect } from 'react';
import { X, Save, Plane, Hotel, MapPin, Music, DollarSign, ListOrdered, Calendar, Ticket, CheckCircle2, Circle } from 'lucide-react';
import { ConcertPlan, BookingStatus } from '../types';

interface ConcertFormProps {
  onClose: () => void;
  onSubmit: (data: any) => void;
  initialData?: ConcertPlan | null;
}

const ConcertForm: React.FC<ConcertFormProps> = ({ onClose, onSubmit, initialData }) => {
  const [formData, setFormData] = useState({
    concertName: initialData?.concertName || '',
    city: initialData?.city || '',
    sessions: initialData?.sessions || '',
    ticketDate: initialData?.ticketDate || new Date().toISOString().split('T')[0],
    ticketSeat: initialData?.ticketSeat || '',
    ticketPrice: initialData?.ticketPrice || 0,
    ticketStatus: initialData?.ticketStatus || 'Pending' as BookingStatus,
    departureFlight1: initialData?.departureFlight1 || '',
    departureFlight2: initialData?.departureFlight2 || '',
    returnFlight1: initialData?.returnFlight1 || '',
    returnFlight2: initialData?.returnFlight2 || '',
    flightCost: initialData?.flightCost || 0,
    flightStatus: initialData?.flightStatus || 'Pending' as BookingStatus,
    hotel1: initialData?.hotel1 || '',
    hotel2: initialData?.hotel2 || '',
    hotelCost: initialData?.hotelCost || 0,
    hotelStatus: initialData?.hotelStatus || 'Pending' as BookingStatus,
  });

  const getDayOfWeek = (dateStr: string) => {
    if (!dateStr) return '';
    const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    const date = new Date(dateStr);
    return isNaN(date.getTime()) ? '' : days[date.getDay()];
  };

  const [weekday, setWeekday] = useState(getDayOfWeek(formData.ticketDate));

  useEffect(() => {
    setWeekday(getDayOfWeek(formData.ticketDate));
  }, [formData.ticketDate]);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  const toggleStatus = (field: 'ticketStatus' | 'flightStatus' | 'hotelStatus') => {
    setFormData(prev => ({
      ...prev,
      [field]: prev[field] === 'Booked' ? 'Pending' : 'Booked'
    }));
  };

  const inputClass = "w-full px-3 py-2 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder:text-slate-300";
  const labelClass = "block text-xs font-black text-slate-400 uppercase tracking-widest mb-1.5 flex items-center gap-1.5";

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-slate-50 w-full max-w-2xl rounded-[2rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-250 flex flex-col max-h-[90vh]">
        <div className="px-8 py-6 bg-white border-b flex justify-between items-center shrink-0">
          <div>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight">{initialData ? '编辑演出计划' : '新增演出计划'}</h2>
            <p className="text-slate-400 text-xs font-bold mt-1 uppercase tracking-widest">Craft your perfect concert trip</p>
          </div>
          <button onClick={onClose} className="p-2.5 text-slate-400 hover:text-slate-600 rounded-2xl hover:bg-slate-100 transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 overflow-y-auto space-y-8">
          {/* Section: Core Info */}
          <section className="space-y-5">
            <div className="flex items-center gap-2 mb-2">
               <div className="w-1.5 h-6 bg-indigo-600 rounded-full" />
               <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">基础信息</h3>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div className="md:col-span-2">
                <label className={labelClass}><Music className="w-3.5 h-3.5" /> 演唱会/演出名称</label>
                <input required value={formData.concertName} onChange={e => setFormData({...formData, concertName: e.target.value})} className={`${inputClass} text-lg font-bold`} placeholder="如：周杰伦 嘉年华世界巡回演唱会" />
              </div>
              <div>
                <label className={labelClass}><MapPin className="w-3.5 h-3.5" /> 城市</label>
                <input required value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} className={inputClass} placeholder="如：上海" />
              </div>
              <div>
                <label className={labelClass}><ListOrdered className="w-3.5 h-3.5" /> 场次说明</label>
                <input required value={formData.sessions} onChange={e => setFormData({...formData, sessions: e.target.value})} className={inputClass} placeholder="如：10/25 周五场" />
              </div>
            </div>
          </section>

          {/* Section: Ticket Info */}
          <section className="space-y-5 p-6 bg-amber-50/50 rounded-3xl border border-amber-100/50 relative">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <div className="w-1.5 h-6 bg-amber-500 rounded-full" />
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">门票详情</h3>
              </div>
              <StatusToggle status={formData.ticketStatus} onToggle={() => toggleStatus('ticketStatus')} label="门票已买到" />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
              <div>
                <label className={labelClass}><Calendar className="w-3.5 h-3.5" /> 演出日期</label>
                <div className="relative">
                  <input type="date" value={formData.ticketDate} onChange={e => setFormData({...formData, ticketDate: e.target.value})} className={inputClass} />
                  <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs font-black text-amber-600 bg-amber-100 px-2 py-1 rounded-lg pointer-events-none">
                    {weekday}
                  </span>
                </div>
              </div>
              <div>
                <label className={labelClass}><MapPin className="w-3.5 h-3.5" /> 位置/看台</label>
                <input value={formData.ticketSeat} onChange={e => setFormData({...formData, ticketSeat: e.target.value})} className={inputClass} placeholder="如：内场 A1区 10排" />
              </div>
              <div>
                <label className={labelClass}><DollarSign className="w-3.5 h-3.5" /> 票面/成交价格</label>
                <input type="number" value={formData.ticketPrice} onChange={e => setFormData({...formData, ticketPrice: Number(e.target.value)})} className={inputClass} />
              </div>
            </div>
          </section>

          {/* Section: Flight */}
          <section className="space-y-5 p-6 bg-blue-50/50 rounded-3xl border border-blue-100/50">
             <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <div className="w-1.5 h-6 bg-blue-500 rounded-full" />
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">交通航班</h3>
              </div>
              <StatusToggle status={formData.flightStatus} onToggle={() => toggleStatus('flightStatus')} label="航班已订好" />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div>
                <label className={labelClass}>去程 1 (或主航段)</label>
                <input value={formData.departureFlight1} onChange={e => setFormData({...formData, departureFlight1: e.target.value})} className={inputClass} placeholder="航班/时间" />
              </div>
              <div>
                <label className={labelClass}>返程 1 (或主航段)</label>
                <input value={formData.returnFlight1} onChange={e => setFormData({...formData, returnFlight1: e.target.value})} className={inputClass} />
              </div>
              <div className="md:col-span-2">
                <label className={labelClass}><DollarSign className="w-3.5 h-3.5" /> 机票费用合计</label>
                <input type="number" value={formData.flightCost} onChange={e => setFormData({...formData, flightCost: Number(e.target.value)})} className={inputClass} />
              </div>
            </div>
          </section>

          {/* Section: Hotel */}
          <section className="space-y-5 p-6 bg-emerald-50/50 rounded-3xl border border-emerald-100/50">
             <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <div className="w-1.5 h-6 bg-emerald-500 rounded-full" />
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">住宿安排</h3>
              </div>
              <StatusToggle status={formData.hotelStatus} onToggle={() => toggleStatus('hotelStatus')} label="酒店已预订" />
            </div>
            <div className="space-y-4">
              <div>
                <label className={labelClass}>入住酒店 1</label>
                <input value={formData.hotel1} onChange={e => setFormData({...formData, hotel1: e.target.value})} className={inputClass} placeholder="酒店名称/地址" />
              </div>
              <div>
                <label className={labelClass}><DollarSign className="w-3.5 h-3.5" /> 酒店费用合计</label>
                <input type="number" value={formData.hotelCost} onChange={e => setFormData({...formData, hotelCost: Number(e.target.value)})} className={inputClass} />
              </div>
            </div>
          </section>

          <div className="pt-4 border-t border-slate-200">
            <div className="flex items-center justify-between bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm">
              <div className="text-slate-400 font-black uppercase tracking-widest text-sm">Estimated Total</div>
              <div className="text-3xl font-black text-indigo-600">¥{(formData.ticketPrice + formData.flightCost + formData.hotelCost).toLocaleString()}</div>
            </div>
          </div>

          <div className="flex gap-4 sticky bottom-0 pt-4 bg-slate-50 pb-2">
            <button type="button" onClick={onClose} className="flex-1 px-6 py-4 border border-slate-200 rounded-[1.5rem] font-bold text-slate-500 hover:bg-white transition-all">
              取消
            </button>
            <button type="submit" className="flex-[2] px-6 py-4 bg-indigo-600 text-white rounded-[1.5rem] font-black shadow-xl shadow-indigo-200 hover:bg-indigo-700 hover:translate-y-[-2px] active:translate-y-[0px] transition-all flex items-center justify-center gap-2 uppercase tracking-widest">
              <Save className="w-5 h-5" />
              保存演出计划
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

const StatusToggle: React.FC<{ status: BookingStatus, onToggle: () => void, label: string }> = ({ status, onToggle, label }) => {
  const isBooked = status === 'Booked';
  return (
    <button 
      type="button" 
      onClick={onToggle}
