  const getDayOfWeek = (dateStr: string) => {
    if (!dateStr) return '';
    const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    const date = new Date(dateStr);
    return isNaN(date.getTime()) ? '' : days[date.getDay()];
  };

  const [weekday, setWeekday] = useState(getDayOfWeek(formData.ticketDate));

  useEffect(() => {
    setWeekday(getDayOfWeek(formData.ticketDate));
