  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    // Clean up empty items before submitting
    const cleaned = {
      ...formData,
      departureFlights: formData.departureFlights.filter(f => f.detail.trim()),
      returnFlights: formData.returnFlights.filter(f => f.detail.trim()),
      hotels: formData.hotels.filter(h => h.name.trim()),
