  const toggleStatus = (field: 'ticketStatus' | 'flightStatus' | 'hotelStatus') => {
    setFormData(prev => ({
      ...prev,
      [field]: prev[field] === 'Booked' ? 'Pending' : 'Booked'
    }));
  };

  const addFlight = (type: 'departure' | 'return') => {
    const key = type === 'departure' ? 'departureFlights' : 'returnFlights';
    setFormData(prev => ({
      ...prev,
      [key]: [...prev[key], { id: crypto.randomUUID(), detail: '' }]
