      ...prev,
      [key]: prev[key].filter(item => item.id !== id)
    }));
  };

  const updateFlight = (type: 'departure' | 'return', id: string, val: string) => {
    const key = type === 'departure' ? 'departureFlights' : 'returnFlights';
    setFormData(prev => ({
      ...prev,
      [key]: prev[key].map(item => item.id === id ? { ...item, detail: val } : item)
    }));
  };

  const addHotel = () => {
    setFormData(prev => ({
      ...prev,
      hotels: [...prev.hotels, { id: crypto.randomUUID(), name: '' }]
    }));
  };

  const removeHotel = (id: string) => {
    setFormData(prev => ({
      ...prev,
      hotels: prev.hotels.filter(item => item.id !== id)
    }));
  };

  const updateHotel = (id: string, val: string) => {
    setFormData(prev => ({
      ...prev,
      hotels: prev.hotels.map(item => item.id === id ? { ...item, name: val } : item)
