        </div>

        <form onSubmit={handleSubmit} className="p-8 overflow-y-auto space-y-8">
          {/* Section: Core Info */}
          <section className="space-y-5">
            <div className="flex items-center gap-2 mb-2">
               <div className="w-1.5 h-6 bg-indigo-600 rounded-full" />
               <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">基础信息</h3>
            </div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div className="md:col-span-2">
                <label className={labelClass}><Music className="w-3.5 h-3.5" /> 演唱会/演出名称</label>
                <input required value={formData.concertName} onChange={e => setFormData({...formData, concertName: e.target.value})} className={`${inputClass} text-lg font-bold`} placeholder="如：周杰伦 嘉年华世界巡回演唱会" />
              </div>
