              </div>
              <div>
                <label className={labelClass}><ListOrdered className="w-3.5 h-3.5" /> 场次说明</label>
                <input required value={formData.sessions} onChange={e => setFormData({...formData, sessions: e.target.value})} className={inputClass} placeholder="如：10/25 周五场" />
              </div>
            </div>
          </section>

          {/* Section: Ticket Info */}
          <section className="space-y-5 p-6 bg-amber-50/50 rounded-3xl border border-amber-100/50 relative">
            <div className="flex items-center justify-between">
              <div className="flex items-center gap-2">
                <div className="w-1.5 h-6 bg-amber-500 rounded-full" />
                <h3 className="text-sm font-black text-slate-800 uppercase tracking-widest">门票详情</h3>
              </div>
