import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plus, Download, Search, Trash2, Edit2, Plane, Hotel, MapPin, 
  Calendar, CreditCard, ChevronDown, Ticket, CheckCircle2, 
  Circle, X, ChevronRight, Info, ExternalLink
} from 'lucide-react';
import { ConcertPlan, SortField, SortOrder } from './types';
import ConcertForm from './components/ConcertForm';
import { exportToExcel } from './services/exportService';

const App: React.FC = () => {
  const [plans, setPlans] = useState<ConcertPlan[]>(() => {
    const saved = localStorage.getItem('concert_plans_v2');
    return saved ? JSON.parse(saved) : [];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPlan, setEditingPlan] = useState<ConcertPlan | null>(null);
  const [viewingPlan, setViewingPlan] = useState<ConcertPlan | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortField, setSortField] = useState<SortField>('ticketDate');
  const [sortOrder, setSortOrder] = useState<SortOrder>('asc');

  useEffect(() => {
    localStorage.setItem('concert_plans_v2', JSON.stringify(plans));
  }, [plans]);

  const filteredAndSortedPlans = useMemo(() => {
    return plans
      .filter(plan => {
        const matchesSearch = 
          plan.concertName.toLowerCase().includes(searchTerm.toLowerCase()) ||
          plan.city.toLowerCase().includes(searchTerm.toLowerCase());
        return matchesSearch;
      })
      .sort((a, b) => {
        let valA: any = a[sortField as keyof ConcertPlan];
        let valB: any = b[sortField as keyof ConcertPlan];

        if (sortField === 'totalCost' as any) {
          valA = a.flightCost + a.hotelCost + a.ticketPrice;
          valB = b.flightCost + b.hotelCost + b.ticketPrice;
        }

        if (valA < valB) return sortOrder === 'asc' ? -1 : 1;
        if (valA > valB) return sortOrder === 'asc' ? 1 : -1;
        return 0;
      });
  }, [plans, searchTerm, sortField, sortOrder]);

  const handleAddPlan = (newPlan: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    const plan: ConcertPlan = {
      ...newPlan,
      id: crypto.randomUUID(),
      createdAt: Date.now(),
    };
    setPlans(prev => [plan, ...prev]);
    setIsModalOpen(false);
  };

  const handleUpdatePlan = (updatedData: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    if (!editingPlan) return;
    setPlans(prev => prev.map(p => p.id === editingPlan.id ? { ...p, ...updatedData } : p));
    setEditingPlan(null);
    setIsModalOpen(false);
    // If we are currently viewing the plan we just updated, update the viewing state too
    if (viewingPlan?.id === editingPlan.id) {
       setViewingPlan(prev => prev ? { ...prev, ...updatedData } : null);
    }
  };

  const handleDeletePlan = (id: string) => {
    if (confirm('确定要删除这个计划吗？')) {
      setPlans(prev => prev.filter(p => p.id !== id));
      if (viewingPlan?.id === id) setViewingPlan(null);
    }
  };

  const openEditModal = (e: React.MouseEvent, plan: ConcertPlan) => {
    e.stopPropagation();
    setEditingPlan(plan);
    setIsModalOpen(true);
  };

  const getDayOfWeek = (dateStr: string) => {
    if (!dateStr) return '';
    const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    const date = new Date(dateStr);
    return days[date.getDay()];
  };

  return (
    <div className="min-h-screen pb-20 md:pb-8 bg-slate-50">
      <header className="bg-white border-b sticky top-0 z-30 px-4 py-4 md:px-8 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl text-white">
              <Calendar className="w-6 h-6" />
            </div>
            <h1 className="text-xl md:text-2xl font-bold bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600">
              Concert Planner Pro
            </h1>
          </div>

          <div className="flex items-center gap-2">
            <button 
              onClick={() => exportToExcel(plans)}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-emerald-50 text-emerald-700 px-4 py-2 rounded-lg border border-emerald-200 hover:bg-emerald-100 transition-all font-medium text-sm"
            >
              <Download className="w-4 h-4" />
              <span>导出 Excel</span>
            </button>
            <button 
              onClick={() => { setEditingPlan(null); setIsModalOpen(true); }}
              className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-6 py-2 rounded-lg hover:bg-indigo-700 transition-all shadow-md hover:shadow-lg font-medium text-sm"
            >
              <Plus className="w-4 h-4" />
              <span>新计划</span>
            </button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6 md:px-8">
        <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm mb-6 flex flex-col md:flex-row gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input 
              type="text" 
              placeholder="搜索演唱会、城市..."
              className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none"
              value={searchTerm}
              onChange={(e) => setSearchTerm(e.target.value)}
            />
          </div>
          <div className="flex gap-2">
