import { ConcertPlan } from '../types';

export const exportToExcel = (plans: ConcertPlan[]) => {
  if (plans.length === 0) {
    alert('没有数据可导出');
    return;
  }

  const excelData = plans.map(plan => ({
    '演出名称': plan.concertName,
    '城市': plan.city,
    '场次': plan.sessions,
    '演出日期': plan.ticketDate,
    '门票位置': plan.ticketSeat,
    '门票价格': plan.ticketPrice,
    '门票状态': plan.ticketStatus === 'Booked' ? '已订' : '待处理',
    '去程路线': plan.departureFlights.map((f, i) => `${i+1}. ${f.detail}`).join('\n'),
    '返程路线': plan.returnFlights.map((f, i) => `${i+1}. ${f.detail}`).join('\n'),
    '机票合计': plan.flightCost,
    '机票状态': plan.flightStatus === 'Booked' ? '已订' : '待处理',
    '酒店列表': plan.hotels.map((h, i) => `${i+1}. ${h.name}`).join('\n'),
    '酒店合计': plan.hotelCost,
    '酒店状态': plan.hotelStatus === 'Booked' ? '已订' : '待处理',
    '总预算': plan.ticketPrice + plan.flightCost + plan.hotelCost,
    '创建时间': new Date(plan.createdAt).toLocaleString()
  }));

  const wb = (window as any).XLSX.utils.book_new();
  const ws = (window as any).XLSX.utils.json_to_sheet(excelData);

  const colWidths = Object.keys(excelData[0]).map(key => ({
    wch: Math.max(key.length * 2, 12)
  }));
  ws['!cols'] = colWidths;

  (window as any).XLSX.utils.book_append_sheet(wb, ws, "演唱会计划表");
  const fileName = `Concert_Itinerary_${new Date().toISOString().slice(0, 10)}.xlsx`;
  (window as any).XLSX.writeFile(wb, fileName);
};

export type BookingStatus = 'Pending' | 'Booked';

export interface TicketItem {
  id: string;
  date: string;
  seat: string;
  price: number;
  status: BookingStatus;
}

export interface FlightSegment {
  id: string;
  detail: string;
}

export interface HotelItem {
  id: string;
  name: string;
  checkIn: string;
  checkOut: string;
  price: number;
}

export interface ConcertPlan {
  id: string;
  concertName: string;
  city: string;

  // Dynamic Lists
  tickets: TicketItem[];
  departureFlights: FlightSegment[];
  returnFlights: FlightSegment[];
  hotels: HotelItem[];

  // Costs
  flightCost: number;
  flightStatus: BookingStatus;

  createdAt: number;
}

export type SortField = 'concertName' | 'city' | 'createdAt' | 'totalCost';
export type SortOrder = 'asc' | 'desc';

import React, { useState } from 'react';
import { X, Save, Plane, Hotel, MapPin, Music, DollarSign, Calendar, Ticket, CheckCircle2, Circle, Plus, Trash2 } from 'lucide-react';
import { ConcertPlan, BookingStatus, FlightSegment, HotelItem, TicketItem } from '../types';

interface ConcertFormProps {
  onClose: () => void;
  onSubmit: (data: any) => void;
  initialData?: ConcertPlan | null;
}

const ConcertForm: React.FC<ConcertFormProps> = ({ onClose, onSubmit, initialData }) => {
  const [formData, setFormData] = useState({
    concertName: initialData?.concertName || '',
    city: initialData?.city || '',

    tickets: initialData?.tickets || [{ 
      id: crypto.randomUUID(), 
      date: new Date().toISOString().split('T')[0], 
      seat: '', 
      price: 0, 
      status: 'Pending' as BookingStatus 
    }],

    departureFlights: initialData?.departureFlights || [{ id: crypto.randomUUID(), detail: '' }],
    returnFlights: initialData?.returnFlights || [{ id: crypto.randomUUID(), detail: '' }],
    flightCost: initialData?.flightCost || 0,
    flightStatus: initialData?.flightStatus || 'Pending' as BookingStatus,

    hotels: initialData?.hotels || [{ 
      id: crypto.randomUUID(), 
      name: '', 
      checkIn: '', 
      checkOut: '', 
      price: 0 
    }],
    hotelStatus: initialData?.flightStatus || 'Pending' as BookingStatus,
  });

  const getDayOfWeek = (dateStr: string) => {
    if (!dateStr) return '';
    const days = ['周日', '周一', '周二', '周三', '周四', '周五', '周六'];
    const date = new Date(dateStr);
    return isNaN(date.getTime()) ? '' : days[date.getDay()];
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    const cleaned = {
      ...formData,
      tickets: formData.tickets.filter(t => t.date),
      departureFlights: formData.departureFlights.filter(f => f.detail.trim()),
      returnFlights: formData.returnFlights.filter(f => f.detail.trim()),
      hotels: formData.hotels.filter(h => h.name.trim()),
    };
    onSubmit(cleaned);
  };

  // Ticket Handlers
  const addTicket = () => {
    setFormData(prev => ({
      ...prev,
      tickets: [...prev.tickets, { id: crypto.randomUUID(), date: '', seat: '', price: 0, status: 'Pending' }]
    }));
  };
  const removeTicket = (id: string) => {
    setFormData(prev => ({ ...prev, tickets: prev.tickets.filter(t => t.id !== id) }));
  };
  const updateTicket = (id: string, updates: Partial<TicketItem>) => {
    setFormData(prev => ({
      ...prev,
      tickets: prev.tickets.map(t => t.id === id ? { ...t, ...updates } : t)
    }));
  };

  // Flight Handlers
  const addFlight = (type: 'departure' | 'return') => {
    const key = type === 'departure' ? 'departureFlights' : 'returnFlights';
    setFormData(prev => ({ ...prev, [key]: [...prev[key as 'departureFlights'], { id: crypto.randomUUID(), detail: '' }] }));
  };
  const updateFlight = (type: 'departure' | 'return', id: string, val: string) => {
    const key = type === 'departure' ? 'departureFlights' : 'returnFlights';
    setFormData(prev => ({ ...prev, [key]: prev[key as 'departureFlights'].map(f => f.id === id ? { ...f, detail: val } : f) }));
  };
  const removeFlight = (type: 'departure' | 'return', id: string) => {
    const key = type === 'departure' ? 'departureFlights' : 'returnFlights';
    setFormData(prev => ({ ...prev, [key]: prev[key as 'departureFlights'].filter(f => f.id !== id) }));
  };

  // Hotel Handlers
  const addHotel = () => {
    setFormData(prev => ({ ...prev, hotels: [...prev.hotels, { id: crypto.randomUUID(), name: '', checkIn: '', checkOut: '', price: 0 }] }));
  };
  const updateHotel = (id: string, updates: Partial<HotelItem>) => {
    setFormData(prev => ({ ...prev, hotels: prev.hotels.map(h => h.id === id ? { ...h, ...updates } : h) }));
  };
  const removeHotel = (id: string) => {
    setFormData(prev => ({ ...prev, hotels: prev.hotels.filter(h => h.id !== id) }));
  };

  const calculateTotal = () => {
    const ticketsTotal = formData.tickets.reduce((sum, t) => sum + (t.price || 0), 0);
    const hotelsTotal = formData.hotels.reduce((sum, h) => sum + (h.price || 0), 0);
    return ticketsTotal + hotelsTotal + (formData.flightCost || 0);
  };

  const inputClass = "w-full px-3 py-2 bg-white border border-slate-200 rounded-xl focus:ring-2 focus:ring-indigo-500 outline-none transition-all placeholder:text-slate-300 text-sm";
  const labelClass = "block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-1 flex items-center gap-1.5";
  const sectionTitleClass = "text-sm font-black text-slate-800 uppercase tracking-widest flex items-center gap-2";

  return (
    <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-md z-50 flex items-center justify-center p-4">
      <div className="bg-slate-50 w-full max-w-2xl rounded-[2rem] shadow-2xl overflow-hidden animate-in fade-in zoom-in duration-250 flex flex-col max-h-[90vh]">
        <div className="px-8 py-6 bg-white border-b flex justify-between items-center shrink-0">
          <div>
            <h2 className="text-2xl font-black text-slate-800 tracking-tight">{initialData ? '编辑演出计划' : '新增演出计划'}</h2>
            <p className="text-slate-400 text-xs font-bold mt-1 uppercase tracking-widest">Detail every show and stay</p>
          </div>
          <button onClick={onClose} className="p-2.5 text-slate-400 hover:text-slate-600 rounded-2xl hover:bg-slate-100 transition-colors">
            <X className="w-6 h-6" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 overflow-y-auto space-y-10">
          {/* Section: Basic Info */}
          <section className="space-y-4">
            <div className={sectionTitleClass}><div className="w-1 h-5 bg-indigo-600 rounded-full" /> 基础信息</div>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
              <div className="md:col-span-1">
                <label className={labelClass}><Music className="w-3 h-3" /> 演出项目名称</label>
                <input required value={formData.concertName} onChange={e => setFormData({...formData, concertName: e.target.value})} className={inputClass} placeholder="如：周杰伦 巡回演唱会" />
              </div>
              <div>
                <label className={labelClass}><MapPin className="w-3 h-3" /> 演出城市</label>
                <input required value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} className={inputClass} placeholder="如：上海" />
              </div>
            </div>
          </section>

          {/* Section: Dynamic Tickets */}
          <section className="space-y-4 p-6 bg-amber-50/40 rounded-3xl border border-amber-100/50">
            <div className="flex justify-between items-center">
              <div className={sectionTitleClass}><div className="w-1 h-5 bg-amber-500 rounded-full" /> 门票条目</div>
              <button type="button" onClick={addTicket} className="text-[10px] font-black uppercase text-amber-600 flex items-center gap-1 hover:underline"><Plus className="w-3.5 h-3.5" /> 增加场次条目</button>
            </div>
            <div className="space-y-4">
              {formData.tickets.map((t, idx) => (
                <div key={t.id} className="p-4 bg-white rounded-2xl border border-amber-200/50 shadow-sm space-y-4 relative group">
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-black text-amber-500 uppercase">场次 #{idx + 1}</span>
                    <div className="flex items-center gap-2">
                      <StatusToggle status={t.status} onToggle={() => updateTicket(t.id, { status: t.status === 'Booked' ? 'Pending' : 'Booked' })} label="已买到" />
                      {formData.tickets.length > 1 && (
                        <button type="button" onClick={() => removeTicket(t.id)} className="p-1 text-red-400 hover:text-red-600"><Trash2 className="w-3.5 h-3.5" /></button>
                      )}
                    </div>
                  </div>
                  <div className="grid grid-cols-1 md:grid-cols-3 gap-3">
                    <div>
                      <label className={labelClass}><Calendar className="w-3 h-3" /> 日期</label>
                      <div className="relative">
                        <input type="date" value={t.date} onChange={e => updateTicket(t.id, { date: e.target.value })} className={inputClass} />
                        <span className="absolute right-2 top-1/2 -translate-y-1/2 text-[9px] font-black bg-amber-100 text-amber-700 px-1 rounded pointer-events-none">{getDayOfWeek(t.date)}</span>
                      </div>
                    </div>
                    <div>
                      <label className={labelClass}><MapPin className="w-3 h-3" /> 位置</label>
                      <input value={t.seat} onChange={e => updateTicket(t.id, { seat: e.target.value })} className={inputClass} placeholder="看台/座位" />
                    </div>
                    <div>
                      <label className={labelClass}><DollarSign className="w-3 h-3" /> 价格</label>
                      <input type="number" value={t.price} onChange={e => updateTicket(t.id, { price: Number(e.target.value) })} className={inputClass} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>

          {/* Section: Flights */}
          <section className="space-y-4 p-6 bg-blue-50/40 rounded-3xl border border-blue-100/50">
            <div className="flex justify-between items-center">
              <div className={sectionTitleClass}><div className="w-1 h-5 bg-blue-500 rounded-full" /> 交通安排</div>
              <StatusToggle status={formData.flightStatus} onToggle={() => setFormData({...formData, flightStatus: formData.flightStatus === 'Booked' ? 'Pending' : 'Booked'})} label="航班已订" />
            </div>
            <div className="space-y-3">
              <label className={labelClass}>去程航段</label>
              {formData.departureFlights.map((f, idx) => (
                <div key={f.id} className="flex gap-2">
                  <input value={f.detail} onChange={e => updateFlight('departure', f.id, e.target.value)} className={inputClass} placeholder={`去程 ${idx + 1} / 时间`} />
                  {formData.departureFlights.length > 1 && <button type="button" onClick={() => removeFlight('departure', f.id)} className="p-2 text-red-300"><Trash2 className="w-4 h-4" /></button>}
                </div>
              ))}
              <button type="button" onClick={() => addFlight('departure')} className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1"><Plus className="w-3 h-3" /> 添加去程航段</button>
            </div>
            <div className="space-y-3">
              <label className={labelClass}>返程航段</label>
              {formData.returnFlights.map((f, idx) => (
                <div key={f.id} className="flex gap-2">
                  <input value={f.detail} onChange={e => updateFlight('return', f.id, e.target.value)} className={inputClass} placeholder={`返程 ${idx + 1} / 时间`} />
                  {formData.returnFlights.length > 1 && <button type="button" onClick={() => removeFlight('return', f.id)} className="p-2 text-red-300"><Trash2 className="w-4 h-4" /></button>}
                </div>
              ))}
              <button type="button" onClick={() => addFlight('return')} className="text-[9px] font-black text-blue-600 uppercase flex items-center gap-1"><Plus className="w-3 h-3" /> 添加返程航段</button>
            </div>
            <div>
              <label className={labelClass}>机票支出合计</label>
              <input type="number" value={formData.flightCost} onChange={e => setFormData({...formData, flightCost: Number(e.target.value)})} className={inputClass} />
            </div>
          </section>

          {/* Section: Detailed Hotels */}
          <section className="space-y-4 p-6 bg-emerald-50/40 rounded-3xl border border-emerald-100/50">
            <div className="flex justify-between items-center">
              <div className={sectionTitleClass}><div className="w-1 h-5 bg-emerald-500 rounded-full" /> 住宿条目</div>
              <div className="flex gap-3 items-center">
                <StatusToggle status={formData.hotelStatus} onToggle={() => setFormData({...formData, hotelStatus: formData.hotelStatus === 'Booked' ? 'Pending' : 'Booked'})} label="已预订" />
                <button type="button" onClick={addHotel} className="text-[10px] font-black uppercase text-emerald-600 flex items-center gap-1 hover:underline"><Plus className="w-3.5 h-3.5" /> 增加换宿段</button>
              </div>
            </div>
            <div className="space-y-4">
              {formData.hotels.map((h, idx) => (
                <div key={h.id} className="p-4 bg-white rounded-2xl border border-emerald-200/50 shadow-sm space-y-3">
                  <div className="flex items-center justify-between">
                    <span className="text-[10px] font-black text-emerald-500 uppercase">换宿段 #{idx + 1}</span>
                    {formData.hotels.length > 1 && <button type="button" onClick={() => removeHotel(h.id)} className="p-1 text-red-300"><Trash2 className="w-3.5 h-3.5" /></button>}
                  </div>
                  <input value={h.name} onChange={e => updateHotel(h.id, { name: e.target.value })} className={inputClass} placeholder="酒店名称及地点" />
                  <div className="grid grid-cols-3 gap-2">
                    <div>
                      <label className={labelClass}>入住日期</label>
                      <input type="date" value={h.checkIn} onChange={e => updateHotel(h.id, { checkIn: e.target.value })} className={inputClass} />
                    </div>
                    <div>
                      <label className={labelClass}>离店日期</label>
                      <input type="date" value={h.checkOut} onChange={e => updateHotel(h.id, { checkOut: e.target.value })} className={inputClass} />
                    </div>
                    <div>
                      <label className={labelClass}>该段费用</label>
                      <input type="number" value={h.price} onChange={e => updateHotel(h.id, { price: Number(e.target.value) })} className={inputClass} />
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </section>

          <div className="pt-4 border-t border-slate-200">
            <div className="flex items-center justify-between bg-white p-6 rounded-[2rem] border border-slate-200 shadow-sm">
              <div className="text-slate-400 font-black uppercase tracking-widest text-xs">Estimated Trip Budget</div>
              <div className="text-3xl font-black text-indigo-600">¥{calculateTotal().toLocaleString()}</div>
            </div>
          </div>

          <div className="flex gap-4 sticky bottom-0 pt-4 bg-slate-50 pb-2">
            <button type="button" onClick={onClose} className="flex-1 px-6 py-4 border border-slate-200 rounded-[1.5rem] font-bold text-slate-500 hover:bg-white transition-all">取消</button>
            <button type="submit" className="flex-[2] px-6 py-4 bg-indigo-600 text-white rounded-[1.5rem] font-black shadow-xl hover:bg-indigo-700 transition-all uppercase tracking-widest flex items-center justify-center gap-2">
              <Save className="w-5 h-5" /> 保存演出行程
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

const StatusToggle: React.FC<{ status: BookingStatus, onToggle: () => void, label: string }> = ({ status, onToggle, label }) => {
  const isBooked = status === 'Booked';
  return (
    <button type="button" onClick={onToggle} className={`flex items-center gap-1.5 px-2 py-1 rounded-xl border transition-all ${isBooked ? 'bg-indigo-600 text-white border-indigo-500' : 'bg-slate-50 text-slate-400 border-slate-100'}`}>
      {isBooked ? <CheckCircle2 className="w-3.5 h-3.5" /> : <Circle className="w-3.5 h-3.5" />}
      <span className="text-[10px] font-black uppercase">{label}</span>
    </button>
  );
};

export default ConcertForm;

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plus, Download, Search, Trash2, Edit2, Plane, Hotel, MapPin, 
  Calendar, CreditCard, ChevronDown, Ticket, CheckCircle2, 
  Circle, X, ChevronRight, Info, Music
} from 'lucide-react';
import { ConcertPlan, SortField, SortOrder } from './types';
import ConcertForm from './components/ConcertForm';
import { exportToExcel } from './services/exportService';

const App: React.FC = () => {
  const [plans, setPlans] = useState<ConcertPlan[]>(() => {
    const saved = localStorage.getItem('concert_plans_v3');
    return saved ? JSON.parse(saved) : [];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPlan, setEditingPlan] = useState<ConcertPlan | null>(null);
  const [viewingPlan, setViewingPlan] = useState<ConcertPlan | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortField, setSortField] = useState<SortField>('createdAt');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');

  useEffect(() => {
    localStorage.setItem('concert_plans_v3', JSON.stringify(plans));
  }, [plans]);

  const calculatePlanTotal = (plan: ConcertPlan) => {
    const t = plan.tickets.reduce((s, x) => s + x.price, 0);
    const h = plan.hotels.reduce((s, x) => s + x.price, 0);
    return t + h + plan.flightCost;
  };

  const filteredAndSortedPlans = useMemo(() => {
    return plans
      .filter(plan => 
        plan.concertName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        plan.city.toLowerCase().includes(searchTerm.toLowerCase())
      )
      .sort((a, b) => {
        let valA: any = a[sortField as keyof ConcertPlan];
        let valB: any = b[sortField as keyof ConcertPlan];

        if (sortField === 'totalCost') {
          valA = calculatePlanTotal(a);
          valB = calculatePlanTotal(b);
        }

        if (valA < valB) return sortOrder === 'asc' ? -1 : 1;
        if (valA > valB) return sortOrder === 'asc' ? 1 : -1;
        return 0;
      });
  }, [plans, searchTerm, sortField, sortOrder]);

  const handleAddPlan = (newPlan: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    const plan: ConcertPlan = { ...newPlan, id: crypto.randomUUID(), createdAt: Date.now() };
    setPlans(prev => [plan, ...prev]);
    setIsModalOpen(false);
  };

  const handleUpdatePlan = (updatedData: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    if (!editingPlan) return;
    setPlans(prev => prev.map(p => p.id === editingPlan.id ? { ...p, ...updatedData } : p));
    setEditingPlan(null);
    setIsModalOpen(false);
    if (viewingPlan?.id === editingPlan.id) setViewingPlan(prev => prev ? { ...prev, ...updatedData } : null);
  };

  const handleDeletePlan = (id: string) => {
    if (confirm('确定要删除这个行程吗？')) {
      setPlans(prev => prev.filter(p => p.id !== id));
      if (viewingPlan?.id === id) setViewingPlan(null);
    }
  };

  const getDayOfWeek = (dateStr: string) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    return ['周日', '周一', '周二', '周三', '周四', '周五', '周六'][date.getDay()];
  };

  const getMergedTicketDates = (tickets: ConcertPlan['tickets']) => {
    if (tickets.length === 0) return '未定日期';
    if (tickets.length === 1) return `${tickets[0].date} (${getDayOfWeek(tickets[0].date)})`;
    const sorted = [...tickets].sort((a,b) => a.date.localeCompare(b.date));
    return `${sorted[0].date} ~ ${sorted[sorted.length-1].date}`;
  };

  return (
    <div className="min-h-screen pb-20 md:pb-8 bg-slate-50">
      <header className="bg-white border-b sticky top-0 z-30 px-4 py-4 md:px-8 shadow-sm">
        <div className="max-w-7xl mx-auto flex flex-col md:flex-row md:items-center justify-between gap-4">
          <div className="flex items-center gap-3">
            <div className="bg-indigo-600 p-2 rounded-xl text-white"><Calendar className="w-6 h-6" /></div>
            <h1 className="text-xl md:text-2xl font-black bg-clip-text text-transparent bg-gradient-to-r from-indigo-600 to-purple-600 uppercase tracking-tight">Concert Planner Pro</h1>
          </div>
          <div className="flex gap-2">
            <button onClick={() => exportToExcel(plans)} className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-emerald-50 text-emerald-700 px-4 py-2 rounded-lg border border-emerald-200 font-bold text-xs"><Download className="w-4 h-4" /> 导出</button>
            <button onClick={() => { setEditingPlan(null); setIsModalOpen(true); }} className="flex-1 md:flex-none flex items-center justify-center gap-2 bg-indigo-600 text-white px-6 py-2 rounded-lg font-black text-xs uppercase tracking-widest"><Plus className="w-4 h-4" /> 新行程</button>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-6 md:px-8">
        <div className="bg-white p-4 rounded-xl border border-slate-200 shadow-sm mb-6 flex flex-col md:flex-row gap-4">
          <div className="relative flex-1">
            <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 w-4 h-4" />
            <input type="text" placeholder="搜索演唱会、城市..." className="w-full pl-10 pr-4 py-2 border border-slate-200 rounded-lg focus:ring-2 focus:ring-indigo-500 outline-none" value={searchTerm} onChange={(e) => setSearchTerm(e.target.value)} />
          </div>
          <select className="px-4 py-2 border border-slate-200 rounded-lg bg-white cursor-pointer text-sm outline-none" value={sortField} onChange={(e) => setSortField(e.target.value as SortField)}>
            <option value="createdAt">按创建日期</option>
            <option value="concertName">按演出名称</option>
            <option value="totalCost">按总费用</option>
          </select>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-5">
          {filteredAndSortedPlans.map(plan => (
            <div key={plan.id} onClick={() => setViewingPlan(plan)} className="bg-white rounded-3xl border border-slate-200 p-6 shadow-sm hover:shadow-xl hover:border-indigo-100 transition-all cursor-pointer group relative overflow-hidden">
              <div className="absolute top-0 left-0 w-1.5 h-full bg-indigo-500 transform -translate-x-full group-hover:translate-x-0 transition-transform" />
              <div className="flex justify-between items-start mb-4">
                <div className="flex-1 min-w-0">
                  <h3 className="text-xl font-black text-slate-900 truncate leading-tight mb-1 group-hover:text-indigo-600 transition-colors">{plan.concertName}</h3>
                  <div className="flex items-center gap-3 text-slate-400 text-xs font-bold">
                    <span className="flex items-center gap-1"><MapPin className="w-3.5 h-3.5 text-indigo-500" /> {plan.city}</span>
                    <span className="flex items-center gap-1"><Ticket className="w-3.5 h-3.5 text-amber-500" /> {plan.tickets.length}场演出</span>
                  </div>
                </div>
                <div className="flex gap-1">
                   <MiniStatusIcon active={plan.tickets.every(t => t.status === 'Booked')} color="amber" icon={<Ticket className="w-3 h-3" />} />
                   <MiniStatusIcon active={plan.flightStatus === 'Booked'} color="blue" icon={<Plane className="w-3 h-3" />} />
                   <MiniStatusIcon active={plan.hotels.length > 0} color="emerald" icon={<Hotel className="w-3 h-3" />} />
                </div>
              </div>

              <div className="bg-slate-50 rounded-2xl p-4 space-y-3 mb-4">
                 <div className="flex justify-between items-center text-[10px] font-black uppercase text-slate-400">
                    <span>行程时间</span>
                    <span className="text-slate-800">{getMergedTicketDates(plan.tickets)}</span>
                 </div>
                 <div className="flex justify-between items-center text-[10px] font-black uppercase text-slate-400">
                    <span>预算概览</span>
                    <span className="text-indigo-600 text-sm">¥{calculatePlanTotal(plan).toLocaleString()}</span>
                 </div>
              </div>

              <div className="flex justify-end gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                 <button onClick={(e) => { e.stopPropagation(); setEditingPlan(plan); setIsModalOpen(true); }} className="p-2 text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all"><Edit2 className="w-4 h-4" /></button>
                 <button onClick={(e) => { e.stopPropagation(); handleDeletePlan(plan.id); }} className="p-2 text-red-500 hover:bg-red-50 rounded-xl transition-all"><Trash2 className="w-4 h-4" /></button>
              </div>
            </div>
          ))}
        </div>

        {filteredAndSortedPlans.length === 0 && (
          <div className="text-center py-32 opacity-30">
            <Music className="w-16 h-16 mx-auto mb-4" />
            <p className="font-bold">暂无演唱会行程记录</p>
          </div>
        )}
      </main>

      {/* Floating Action Button */}
      <button onClick={() => { setEditingPlan(null); setIsModalOpen(true); }} className="fixed bottom-8 right-8 w-16 h-16 bg-indigo-600 text-white rounded-full shadow-2xl flex items-center justify-center hover:scale-110 active:scale-95 transition-all z-40"><Plus className="w-10 h-10" /></button>

      {/* Detail View Drawer */}
      {viewingPlan && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-slate-900/40 backdrop-blur-sm" onClick={() => setViewingPlan(null)} />
          <div className="relative w-full max-w-lg bg-slate-50 h-full shadow-2xl overflow-y-auto animate-in slide-in-from-right duration-300">
            <div className="sticky top-0 bg-white px-6 py-4 border-b flex justify-between items-center z-10">
              <h2 className="text-xl font-black text-slate-900">行程详情</h2>
              <button onClick={() => setViewingPlan(null)} className="p-2 text-slate-400 hover:text-slate-900"><X className="w-6 h-6" /></button>
            </div>

            <div className="p-6 space-y-6">
              <div className="bg-gradient-to-br from-indigo-600 to-purple-700 rounded-3xl p-6 text-white shadow-xl">
                 <h3 className="text-3xl font-black leading-tight mb-2 uppercase">{viewingPlan.concertName}</h3>
                 <div className="flex items-center gap-4 text-sm font-bold opacity-80">
                   <div className="flex items-center gap-1.5"><MapPin className="w-4 h-4" /> {viewingPlan.city}</div>
                   <div className="flex items-center gap-1.5"><Calendar className="w-4 h-4" /> {getMergedTicketDates(viewingPlan.tickets)}</div>
                 </div>
              </div>

              {/* Tickets Detail */}
              <DetailSection title="门票安排" icon={<Ticket className="w-5 h-5" />}>
                 <div className="space-y-4">
                    {viewingPlan.tickets.map((t, idx) => (
                      <div key={t.id} className="bg-amber-50/50 p-4 rounded-2xl border border-amber-100 flex justify-between items-center">
                         <div>
                            <div className="text-xs font-black text-amber-600 uppercase mb-0.5">场次 #{idx + 1}</div>
                            <div className="text-sm font-bold text-slate-800">{t.date} ({getDayOfWeek(t.date)})</div>
                            <div className="text-[10px] text-slate-500">{t.seat || '位置未填'}</div>
                         </div>
                         <div className="text-right">
                            <div className={`text-[10px] font-black px-2 py-0.5 rounded-full mb-1 ${t.status === 'Booked' ? 'bg-amber-500 text-white' : 'bg-slate-200 text-slate-500'}`}>{t.status === 'Booked' ? '已订' : '待买'}</div>
                            <div className="text-sm font-black text-indigo-600">¥{t.price}</div>
                         </div>
                      </div>
                    ))}
                 </div>
              </DetailSection>

              {/* Transportation Detail */}
              <DetailSection title="交通路线" icon={<Plane className="w-5 h-5" />}>
                 <div className="space-y-4">
                    <TimelineGroup title="去程航段" items={viewingPlan.departureFlights.map(f => f.detail)} color="blue" />
                    <TimelineGroup title="返程航段" items={viewingPlan.returnFlights.map(f => f.detail)} color="indigo" />
                    <div className="flex justify-between items-center pt-2 border-t text-sm">
                       <span className="font-bold text-slate-400">交通支出合计</span>
                       <span className="font-black text-indigo-600">¥{viewingPlan.flightCost}</span>
                    </div>
                 </div>
              </DetailSection>

              {/* Hotel Detail */}
              <DetailSection title="住宿记录" icon={<Hotel className="w-5 h-5" />}>
                 <div className="space-y-4">
                    {viewingPlan.hotels.map((h, idx) => (
                      <div key={h.id} className="bg-emerald-50/50 p-4 rounded-2xl border border-emerald-100 space-y-2">
                         <div className="flex justify-between items-start">
                            <div className="text-xs font-black text-emerald-600 uppercase">换宿 #{idx + 1}</div>
                            <div className="text-xs font-black text-indigo-600">¥{h.price}</div>
                         </div>
                         <div className="text-sm font-bold text-slate-800">{h.name || '未填名称'}</div>
                         <div className="flex items-center gap-2 text-[10px] font-bold text-slate-500">
                            <span>{h.checkIn || '??'}</span>
                            <ChevronRight className="w-3 h-3" />
                            <span>{h.checkOut || '??'}</span>
                         </div>
                      </div>
                    ))}
                    <div className="flex justify-between items-center pt-2 border-t text-sm">
                       <span className="font-bold text-slate-400">住宿支出合计</span>
                       <span className="font-black text-indigo-600">¥{viewingPlan.hotels.reduce((s,x)=>s+x.price,0)}</span>
                    </div>
                 </div>
              </DetailSection>

              <div className="bg-white rounded-3xl p-6 border border-slate-200 shadow-inner flex items-center justify-between">
                <div className="text-slate-400 font-black uppercase tracking-widest text-sm">Trip Total</div>
                <div className="text-3xl font-black text-indigo-600">¥{calculatePlanTotal(viewingPlan).toLocaleString()}</div>
              </div>
            </div>
          </div>
        </div>
      )}

      {isModalOpen && <ConcertForm onClose={() => setIsModalOpen(false)} onSubmit={editingPlan ? handleUpdatePlan : handleAddPlan} initialData={editingPlan} />}
    </div>
  );
};

const MiniStatusIcon: React.FC<{ active: boolean, color: string, icon: React.ReactNode }> = ({ active, color, icon }) => (
  <div className={`p-1.5 rounded-lg border transition-all ${active ? `bg-${color}-500 text-white border-${color}-600` : 'bg-slate-50 text-slate-300 border-slate-100'}`}>{icon}</div>
);

const DetailSection: React.FC<{ title: string, icon: React.ReactNode, children: React.ReactNode }> = ({ title, icon, children }) => (
  <div className="bg-white rounded-3xl border border-slate-200 overflow-hidden shadow-sm">
