import { ConcertPlan } from '../types';

export const exportToExcel = (plans: ConcertPlan[]) => {
  if (plans.length === 0) {
    alert('没有数据可导出');
    return;
  }

  const excelData = plans.map(plan => {
    const totalTicketPrice = plan.tickets.reduce((sum, t) => sum + t.price, 0);
    const totalHotelPrice = plan.hotels.reduce((sum, h) => sum + h.price, 0);

    return {
      '项目名称': plan.concertName,
      '城市': plan.city,
      '场次详情': plan.tickets.map((t, i) => `场次${i+1}: ${t.date} ${t.seat} (¥${t.price})`).join('\n'),
      '门票状态': plan.tickets.every(t => t.status === 'Booked') ? '全部买到' : '部分/全部待买',
      '去程航段': plan.departureFlights.map((f, i) => `${i+1}. ${f.detail}`).join('\n'),
      '返程航段': plan.returnFlights.map((f, i) => `${i+1}. ${f.detail}`).join('\n'),
      '机票总计': plan.flightCost,
      '住宿详情': plan.hotels.map((h, i) => `${i+1}. ${h.name} (${h.checkIn}~${h.checkOut}) ¥${h.price}`).join('\n'),
      '住宿总计': totalHotelPrice,
      '门票总计': totalTicketPrice,
      '整个行程总预算': plan.flightCost + totalHotelPrice + totalTicketPrice,
      '记录时间': new Date(plan.createdAt).toLocaleString()
    };
  });

  const wb = (window as any).XLSX.utils.book_new();
  const ws = (window as any).XLSX.utils.json_to_sheet(excelData);

  const colWidths = Object.keys(excelData[0]).map(key => ({
    wch: Math.max(key.length * 2, 15)
  }));
  ws['!cols'] = colWidths;

  (window as any).XLSX.utils.book_append_sheet(wb, ws, "演唱会行程表");
  const fileName = `Concert_Planner_${new Date().toISOString().slice(0, 10)}.xlsx`;
  (window as any).XLSX.writeFile(wb, fileName);
};

import React, { useState, useEffect, useMemo } from 'react';
import { 
  Plus, Download, Search, Trash2, Edit2, Plane, Hotel, MapPin, 
  Calendar, CreditCard, ChevronDown, Ticket, CheckCircle2, 
  Circle, X, ChevronRight, Music, Globe
} from 'lucide-react';
import { ConcertPlan, SortField, SortOrder } from './types';
import ConcertForm from './components/ConcertForm';
import { exportToExcel } from './services/exportService';

const App: React.FC = () => {
  const [plans, setPlans] = useState<ConcertPlan[]>(() => {
    const saved = localStorage.getItem('concert_plans_v4');
    return saved ? JSON.parse(saved) : [];
  });

  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPlan, setEditingPlan] = useState<ConcertPlan | null>(null);
  const [viewingPlan, setViewingPlan] = useState<ConcertPlan | null>(null);
  const [searchTerm, setSearchTerm] = useState('');
  const [sortField, setSortField] = useState<SortField>('createdAt');
  const [sortOrder, setSortOrder] = useState<SortOrder>('desc');

  useEffect(() => {
    localStorage.setItem('concert_plans_v4', JSON.stringify(plans));
  }, [plans]);

  const calculatePlanTotal = (plan: ConcertPlan) => {
    const t = plan.tickets.reduce((s, x) => s + x.price, 0);
    const h = plan.hotels.reduce((s, x) => s + x.price, 0);
    return t + h + plan.flightCost;
  };

  const filteredAndSortedPlans = useMemo(() => {
    return plans
      .filter(plan => 
        plan.concertName.toLowerCase().includes(searchTerm.toLowerCase()) ||
        plan.city.toLowerCase().includes(searchTerm.toLowerCase())
      )
      .sort((a, b) => {
        let valA: any = a[sortField as keyof ConcertPlan];
        let valB: any = b[sortField as keyof ConcertPlan];
        if (sortField === 'totalCost') {
          valA = calculatePlanTotal(a);
          valB = calculatePlanTotal(b);
        }
        if (valA < valB) return sortOrder === 'asc' ? -1 : 1;
        if (valA > valB) return sortOrder === 'asc' ? 1 : -1;
        return 0;
      });
  }, [plans, searchTerm, sortField, sortOrder]);

  const handleAddPlan = (newPlan: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    const plan: ConcertPlan = { ...newPlan, id: crypto.randomUUID(), createdAt: Date.now() };
    setPlans(prev => [plan, ...prev]);
    setIsModalOpen(false);
  };

  const handleUpdatePlan = (updatedData: Omit<ConcertPlan, 'id' | 'createdAt'>) => {
    if (!editingPlan) return;
    setPlans(prev => prev.map(p => p.id === editingPlan.id ? { ...p, ...updatedData } : p));
    setEditingPlan(null);
    setIsModalOpen(false);
    if (viewingPlan?.id === editingPlan.id) setViewingPlan(prev => prev ? { ...prev, ...updatedData } : null);
  };

  const handleDeletePlan = (id: string) => {
    if (confirm('确定要删除这个计划吗？')) {
      setPlans(prev => prev.filter(p => p.id !== id));
      if (viewingPlan?.id === id) setViewingPlan(null);
    }
  };

  const getDayOfWeek = (dateStr: string) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    return ['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT'][date.getDay()];
  };

  const getMergedTicketDates = (tickets: ConcertPlan['tickets']) => {
    if (tickets.length === 0) return 'TBA';
    const sorted = [...tickets].sort((a,b) => a.date.localeCompare(b.date));
    if (tickets.length === 1) return `${sorted[0].date} (${getDayOfWeek(sorted[0].date)})`;
    return `${sorted[0].date} - ${sorted[sorted.length-1].date}`;
  };

  return (
    <div className="min-h-screen pb-20 md:pb-8 relative overflow-hidden">
      {/* Horizon Background Glow */}
      <div className="fixed top-0 left-0 w-full h-[60vh] horizon-glow pointer-events-none -z-10" />

      <header className="px-6 py-10 md:px-12 text-center relative">
        <div className="inline-block px-4 py-1 border border-white/20 rounded-full text-[10px] tracking-[0.4em] font-black text-white/40 mb-4 uppercase">
          PLANET ADVENTURE
        </div>
        <h1 className="font-serif-epic text-5xl md:text-7xl font-black text-white tracking-tighter mb-4 drop-shadow-2xl">
          EXhOrizon
        </h1>
        <p className="font-serif-epic text-xs md:text-sm text-slate-400 tracking-[0.3em] uppercase">
          Concert Travel Ledger
        </p>
      </header>

      <main className="max-w-6xl mx-auto px-6 relative">
        <div className="flex flex-col md:flex-row gap-4 mb-12">
          <div className="relative flex-1 group">
            <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-500 w-4 h-4 group-focus-within:text-white transition-colors" />
            <input 
              type="text" 
              placeholder="SEARCH TOUR CITY OR TITLE..." 
              className="w-full pl-12 pr-4 py-3 bg-white/5 border border-white/10 rounded-full focus:ring-1 focus:ring-white/30 outline-none text-xs tracking-widest uppercase transition-all placeholder:text-slate-600" 
              value={searchTerm} 
              onChange={(e) => setSearchTerm(e.target.value)} 
            />
          </div>
          <div className="flex gap-2">
             <button onClick={() => exportToExcel(plans)} className="px-6 py-3 bg-white/5 border border-white/10 rounded-full text-[10px] font-black tracking-widest uppercase hover:bg-white/10 transition-all flex items-center gap-2">
               <Download className="w-4 h-4" /> 导出
             </button>
             <button onClick={() => { setEditingPlan(null); setIsModalOpen(true); }} className="px-8 py-3 bg-white text-black rounded-full text-[10px] font-black tracking-widest uppercase hover:scale-105 active:scale-95 transition-all flex items-center gap-2 shadow-[0_0_20px_rgba(255,255,255,0.2)]">
               <Plus className="w-4 h-4" /> 新计划
             </button>
          </div>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {filteredAndSortedPlans.map(plan => (
            <div 
              key={plan.id} 
              onClick={() => setViewingPlan(plan)} 
              className="card-glass group p-8 rounded-[2rem] hover:border-white/40 transition-all cursor-pointer relative overflow-hidden"
            >
              <div className="absolute top-0 right-0 p-4 opacity-20">
                <Globe className="w-12 h-12" />
              </div>

              <div className="mb-8">
                <div className="text-[10px] font-black text-white/30 tracking-[0.2em] mb-2 uppercase flex items-center gap-2">
                  <MapPin className="w-3 h-3" /> {plan.city}
                </div>
                <h3 className="font-serif-epic text-2xl font-bold text-white leading-none group-hover:tracking-wider transition-all duration-500">
                  {plan.concertName}
                </h3>
              </div>

              <div className="space-y-4 mb-8">
                <div className="flex justify-between items-end border-b border-white/5 pb-2">
                  <div className="text-[9px] font-black text-slate-500 tracking-widest uppercase">Schedule</div>
                  <div className="text-[11px] font-bold text-slate-300">{getMergedTicketDates(plan.tickets)}</div>
                </div>
                <div className="flex justify-between items-end border-b border-white/5 pb-2">
                  <div className="text-[9px] font-black text-slate-500 tracking-widest uppercase">Status</div>
                  <div className="flex gap-1.5">
                    <MiniDot active={plan.tickets.every(t => t.status === 'Booked')} />
                    <MiniDot active={plan.flightStatus === 'Booked'} />
                    <MiniDot active={plan.hotels.length > 0} />
                  </div>
                </div>
              </div>

              <div className="flex justify-between items-center">
                <div className="text-xl font-black text-white">
                  <span className="text-[10px] text-slate-500 mr-2 uppercase tracking-tighter">Total</span>
                  ¥{calculatePlanTotal(plan).toLocaleString()}
                </div>
                <div className="flex gap-1 opacity-0 group-hover:opacity-100 transition-all translate-x-4 group-hover:translate-x-0">
                   <button onClick={(e) => { e.stopPropagation(); setEditingPlan(plan); setIsModalOpen(true); }} className="p-2 hover:text-white text-slate-500"><Edit2 className="w-4 h-4" /></button>
                   <button onClick={(e) => { e.stopPropagation(); handleDeletePlan(plan.id); }} className="p-2 hover:text-red-400 text-slate-500"><Trash2 className="w-4 h-4" /></button>
                </div>
              </div>
            </div>
          ))}
        </div>

        {filteredAndSortedPlans.length === 0 && (
          <div className="text-center py-40 border-t border-white/5 mt-20">
            <div className="font-serif-epic text-2xl text-slate-700 tracking-[0.5em] uppercase">No Horizons Found</div>
            <button onClick={() => setIsModalOpen(true)} className="mt-6 text-[10px] font-black text-white/40 uppercase tracking-widest hover:text-white transition-colors">Start your journey</button>
          </div>
        )}
      </main>

      {/* Floating Button - Mobile only */}
      <button onClick={() => setIsModalOpen(true)} className="md:hidden fixed bottom-8 right-8 w-16 h-16 bg-white text-black rounded-full shadow-2xl flex items-center justify-center z-40">
        <Plus className="w-8 h-8" />
      </button>

      {/* Detail Drawer */}
      {viewingPlan && (
        <div className="fixed inset-0 z-50 flex justify-end">
          <div className="absolute inset-0 bg-black/80 backdrop-blur-md" onClick={() => setViewingPlan(null)} />
          <div className="relative w-full max-w-xl bg-[#0f172a] h-full shadow-2xl overflow-y-auto animate-in slide-in-from-right duration-500 border-l border-white/10">

            <div className="sticky top-0 bg-[#0f172a]/80 backdrop-blur-xl px-8 py-6 flex justify-between items-center border-b border-white/5 z-20">
               <div className="font-serif-epic text-sm tracking-[0.3em] text-white/40 uppercase">Itinerary Details</div>
               <button onClick={() => setViewingPlan(null)} className="p-2 text-slate-500 hover:text-white"><X className="w-6 h-6" /></button>
            </div>

            <div className="p-8 space-y-12 pb-32">
              <div className="text-center space-y-4">
                <div className="inline-block px-3 py-1 bg-white/5 rounded-full text-[10px] font-black text-white/40 tracking-widest uppercase">{viewingPlan.city}</div>
                <h2 className="font-serif-epic text-5xl font-black text-white tracking-tighter">{viewingPlan.concertName}</h2>
                <div className="text-xs font-bold text-slate-500 tracking-widest">{getMergedTicketDates(viewingPlan.tickets)}</div>
              </div>

              <Section title="Tickets" icon={<Ticket className="w-5 h-5" />}>
                <div className="space-y-4">
                  {viewingPlan.tickets.map((t, i) => (
                    <div key={t.id} className="p-6 bg-white/5 rounded-3xl border border-white/5 flex justify-between items-center group">
                      <div>
                        <div className="text-[10px] font-black text-white/30 uppercase tracking-widest mb-1">Session {i+1}</div>
                        <div className="text-lg font-bold text-white mb-0.5">{t.date} <span className="text-xs text-slate-500">({getDayOfWeek(t.date)})</span></div>
                        <div className="text-xs text-slate-400 font-medium tracking-wide italic">{t.seat || 'No seat info'}</div>
                      </div>
                      <div className="text-right">
                        <div className={`inline-block px-3 py-1 rounded-full text-[9px] font-black uppercase tracking-widest mb-3 ${t.status === 'Booked' ? 'bg-white text-black' : 'bg-white/10 text-slate-500'}`}>
                          {t.status === 'Booked' ? 'Booked' : 'Pending'}
                        </div>
                        <div className="text-xl font-black text-white tracking-tighter">¥{t.price}</div>
                      </div>
                    </div>
                  ))}
                </div>
              </Section>

              <Section title="Transportation" icon={<Plane className="w-5 h-5" />}>
                 <div className="space-y-6">
                    <Timeline title="Departure" items={viewingPlan.departureFlights.map(f => f.detail)} color="white" />
                    <Timeline title="Return" items={viewingPlan.returnFlights.map(f => f.detail)} color="slate-500" />
                    <div className="flex justify-between items-center pt-6 border-t border-white/5">
                      <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Transport Cost</div>
                      <div className="text-xl font-black text-white tracking-tighter">¥{viewingPlan.flightCost}</div>
                    </div>
                 </div>
              </Section>

              <Section title="Accommodations" icon={<Hotel className="w-5 h-5" />}>
                 <div className="space-y-6">
                    {viewingPlan.hotels.map((h, i) => (
                      <div key={h.id} className="relative pl-8">
