                        </div>
                      </div>
                    ))}
                    <div className="flex justify-between items-center pt-6 border-t border-white/5">
                      <div className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Hotel Total</div>
                      <div className="text-xl font-black text-white tracking-tighter">¥{viewingPlan.hotels.reduce((s,x)=>s+x.price,0)}</div>
                    </div>
                 </div>
              </Section>

              <div className="bg-white p-8 rounded-[2.5rem] flex justify-between items-center shadow-[0_0_40px_rgba(255,255,255,0.1)]">
                 <div className="text-black font-black uppercase text-xs tracking-[0.2em]">Grand Total</div>
                 <div className="text-4xl font-black text-black tracking-tighter">¥{calculatePlanTotal(viewingPlan).toLocaleString()}</div>
              </div>
            </div>
          </div>
        </div>
      )}

      {isModalOpen && (
        <ConcertForm 
          onClose={() => setIsModalOpen(false)} 
          onSubmit={editingPlan ? handleUpdatePlan : handleAddPlan} 
          initialData={editingPlan} 
        />
