import React, { useState } from 'react';
import { X, Save, Plane, Hotel, MapPin, Music, DollarSign, Calendar, Ticket, CheckCircle2, Circle, Plus, Trash2 } from 'lucide-react';
import { ConcertPlan, BookingStatus, FlightSegment, HotelItem, TicketItem } from '../types';

interface ConcertFormProps {
  onClose: () => void;
  onSubmit: (data: any) => void;
  initialData?: ConcertPlan | null;
}

const ConcertForm: React.FC<ConcertFormProps> = ({ onClose, onSubmit, initialData }) => {
  const [formData, setFormData] = useState({
    concertName: initialData?.concertName || '',
    city: initialData?.city || '',
    tickets: initialData?.tickets || [{ 
      id: crypto.randomUUID(), 
      date: new Date().toISOString().split('T')[0], 
      seat: '', 
      price: 0, 
      status: 'Pending' as BookingStatus 
    }],
    departureFlights: initialData?.departureFlights || [{ id: crypto.randomUUID(), detail: '' }],
    returnFlights: initialData?.returnFlights || [{ id: crypto.randomUUID(), detail: '' }],
    flightCost: initialData?.flightCost || 0,
    flightStatus: initialData?.flightStatus || 'Pending' as BookingStatus,
    hotels: initialData?.hotels || [{ 
      id: crypto.randomUUID(), 
      name: '', 
      checkIn: '', 
      checkOut: '', 
      price: 0 
    }],
    hotelStatus: initialData?.hotelStatus || 'Pending' as BookingStatus,
  });

  const getDayOfWeek = (dateStr: string) => {
    if (!dateStr) return '';
    const date = new Date(dateStr);
    return isNaN(date.getTime()) ? '' : ['SUN', 'MON', 'TUE', 'WED', 'THU', 'FRI', 'SAT'][date.getDay()];
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    onSubmit(formData);
  };

  // Generic Handlers
  const addTicket = () => setFormData(p => ({ ...p, tickets: [...p.tickets, { id: crypto.randomUUID(), date: '', seat: '', price: 0, status: 'Pending' }] }));
  const addFlight = (type: 'departure' | 'return') => setFormData(p => ({ ...p, [type === 'departure' ? 'departureFlights' : 'returnFlights']: [...p[type === 'departure' ? 'departureFlights' : 'returnFlights'], { id: crypto.randomUUID(), detail: '' }] }));
  const addHotel = () => setFormData(p => ({ ...p, hotels: [...p.hotels, { id: crypto.randomUUID(), name: '', checkIn: '', checkOut: '', price: 0 }] }));

  const inputClass = "w-full px-4 py-3 bg-white/5 border border-white/10 rounded-2xl focus:ring-1 focus:ring-white/40 outline-none text-white transition-all placeholder:text-slate-600 text-sm tracking-wide";
  const labelClass = "block text-[10px] font-black text-slate-500 uppercase tracking-[0.2em] mb-2 px-1";

  return (
    <div className="fixed inset-0 bg-black/90 backdrop-blur-xl z-[60] flex items-center justify-center p-4">
      <div className="bg-[#0f172a] w-full max-w-3xl rounded-[3rem] border border-white/10 shadow-2xl overflow-hidden flex flex-col max-h-[90vh]">
        <div className="px-10 py-8 bg-white/5 border-b border-white/5 flex justify-between items-center">
          <div>
            <h2 className="font-serif-epic text-2xl font-bold text-white tracking-widest">{initialData ? 'EDIT JOURNEY' : 'NEW ADVENTURE'}</h2>
            <p className="text-[10px] font-black text-slate-500 tracking-[0.3em] uppercase mt-1">Horizon Data Entry</p>
          </div>
          <button onClick={onClose} className="p-3 text-slate-500 hover:text-white transition-colors"><X className="w-6 h-6" /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-10 overflow-y-auto space-y-12">
          {/* Main Info */}
          <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
            <div className="md:col-span-1">
              <label className={labelClass}>CONCERT TITLE</label>
              <input required value={formData.concertName} onChange={e => setFormData({...formData, concertName: e.target.value})} className={inputClass} placeholder="EXO PLANET #6..." />
            </div>
            <div>
              <label className={labelClass}>CITY</label>
              <input required value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} className={inputClass} placeholder="SEOUL, BANGKOK..." />
            </div>
          </div>

          {/* Dynamic Tickets */}
          <div className="space-y-6">
            <div className="flex justify-between items-center px-1">
               <h3 className="font-serif-epic text-sm font-bold text-white tracking-[0.2em] uppercase">SESSIONS</h3>
               <button type="button" onClick={addTicket} className="text-[9px] font-black text-white/40 uppercase tracking-widest hover:text-white transition-all flex items-center gap-1"><Plus className="w-3 h-3" /> Add Show</button>
