export default ConcertForm;

export type BookingStatus = 'Pending' | 'Booked';

export interface TicketItem {
  id: string;
  date: string;
  seat: string;
  price: number;
  status: BookingStatus;
}

export interface FlightSegment {
  id: string;
  flightNo: string;    // 航班号
  depAirport: string;  // 起飞机场
  arrAirport: string;  // 到达机场
  depTime: string;     // 起飞时间 (YYYY-MM-DD HH:mm)
  arrTime: string;     // 到达时间
  price: number;       // 该航段价格
}

export interface HotelItem {
  id: string;
  name: string;
  checkIn: string;
  checkOut: string;
  price: number;
}

export interface ConcertPlan {
  id: string;
  concertName: string;
  city: string;

  tickets: TicketItem[];
  departureFlights: FlightSegment[];
  returnFlights: FlightSegment[];
  hotels: HotelItem[];

  flightStatus: BookingStatus;
  hotelStatus: BookingStatus;

  remarks: string; // 新增备注字段
  createdAt: number;
}

export type SortField = 'concertName' | 'city' | 'createdAt' | 'totalCost';
export type SortOrder = 'asc' | 'desc';

import React, { useState } from 'react';
import { X, Save, Plane, Hotel, Trash2, Plus, MessageSquare } from 'lucide-react';
import { ConcertPlan, BookingStatus, FlightSegment, HotelItem, TicketItem } from '../types';

interface ConcertFormProps {
  onClose: () => void;
  onSubmit: (data: any) => void;
  initialData?: ConcertPlan | null;
}

const ConcertForm: React.FC<ConcertFormProps> = ({ onClose, onSubmit, initialData }) => {
  const [formData, setFormData] = useState({
    concertName: initialData?.concertName || '',
    city: initialData?.city || '',
    tickets: initialData?.tickets || [{ id: crypto.randomUUID(), date: '', seat: '', price: 0, status: 'Pending' as BookingStatus }],
    departureFlights: initialData?.departureFlights || [{ id: crypto.randomUUID(), flightNo: '', depAirport: '', arrAirport: '', depTime: '', arrTime: '', price: 0 }],
    returnFlights: initialData?.returnFlights || [{ id: crypto.randomUUID(), flightNo: '', depAirport: '', arrAirport: '', depTime: '', arrTime: '', price: 0 }],
    hotels: initialData?.hotels || [{ id: crypto.randomUUID(), name: '', checkIn: '', checkOut: '', price: 0 }],
    flightStatus: initialData?.flightStatus || 'Pending' as BookingStatus,
    hotelStatus: initialData?.hotelStatus || 'Pending' as BookingStatus,
    remarks: initialData?.remarks || '',
