  return (
    <div className="fixed inset-0 bg-black/95 backdrop-blur-2xl z-[1000] flex items-center justify-center p-4">
      <div className="bg-[#0f172a] w-full max-w-4xl rounded-[3.5rem] border border-white/10 shadow-2xl overflow-hidden flex flex-col max-h-[95vh]">
        <div className="px-12 py-10 bg-white/5 border-b border-white/5 flex justify-between items-center">
          <div>
            <h2 className="font-serif-epic text-2xl font-bold text-white tracking-[0.3em] uppercase">{initialData ? 'EDIT ADVENTURE' : 'NEW HORIZON'}</h2>
            <p className="text-[9px] font-black text-slate-600 tracking-[0.5em] uppercase mt-2">DATA ENTRY SYSTEM</p>
          </div>
          <button onClick={onClose} className="p-4 text-slate-600 hover:text-white transition-colors"><X className="w-8 h-8" /></button>
        </div>

        <form onSubmit={handleSubmit} className="p-12 overflow-y-auto space-y-16">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
            <div>
              <label className={labelClass}>巡演项目全称</label>
              <input required value={formData.concertName} onChange={e => setFormData({...formData, concertName: e.target.value})} className={inputClass} placeholder="例如：EXO PLANET #6 - EXhOrizon" />
            </div>
            <div>
              <label className={labelClass}>目的地城市</label>
              <input required value={formData.city} onChange={e => setFormData({...formData, city: e.target.value})} className={inputClass} placeholder="例如：SEOUL" />
            </div>
          </div>

          <SectionHeader title="演出场次" onAdd={() => setFormData(p => ({...p, tickets: [...p.tickets, {id: crypto.randomUUID(), date:'', seat:'', price:0, status:'Pending'}]}))} />
          {formData.tickets.map((t, i) => (
            <div key={t.id} className="p-8 bg-white/5 rounded-[2.5rem] border border-white/5 space-y-6 relative group">
              <div className="flex justify-between items-center">
                <span className="text-[9px] font-black text-slate-600 tracking-widest uppercase">STAGE #{i+1}</span>
                <div className="flex items-center gap-4">
                  <StatusSwitch active={t.status === 'Booked'} onToggle={() => updateItem('tickets', t.id, {status: t.status === 'Booked' ? 'Pending' : 'Booked'})} />
                  {formData.tickets.length > 1 && <button type="button" onClick={() => setFormData(p => ({...p, tickets: p.tickets.filter(x => x.id !== t.id)}))} className="text-red-900 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>}
                </div>
              </div>
              <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
                <div><label className={labelClass}>演出日期</label><input type="date" value={t.date} onChange={e => updateItem('tickets', t.id, {date: e.target.value})} className={inputClass} /></div>
                <div><label className={labelClass}>座位备注</label><input value={t.seat} onChange={e => updateItem('tickets', t.id, {seat: e.target.value})} className={inputClass} placeholder="例如：VIP A区" /></div>
                <div><label className={labelClass}>门票价格</label><input type="number" value={t.price} onChange={e => updateItem('tickets', t.id, {price: Number(e.target.value)})} className={inputClass} /></div>
              </div>
            </div>
          ))}

          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <SectionHeader title="交通行程" onAdd={() => {}} hideButton />
              <StatusSwitch active={formData.flightStatus === 'Booked'} onToggle={() => setFormData(p => ({...p, flightStatus: p.flightStatus === 'Booked' ? 'Pending' : 'Booked'}))} />
            </div>
            {['departureFlights', 'returnFlights'].map(type => (
              <React.Fragment key={type}>
                <div className="flex justify-between items-center px-2 mt-4">
                  <h4 className="text-[10px] font-black text-slate-600 uppercase tracking-widest">{type === 'departureFlights' ? '去程航段' : '返程航段'}</h4>
                  <button type="button" onClick={() => setFormData(p => ({...(p as any), [type]: [...(p as any)[type], {id: crypto.randomUUID(), flightNo:'', depAirport:'', arrAirport:'', depTime:'', arrTime:'', price:0}]}))} className="text-[9px] font-black text-white/30 hover:text-white uppercase transition-colors">+ 增加条目</button>
                </div>
                {(formData as any)[type].map((f: any, i: number) => (
                  <div key={f.id} className="p-8 bg-white/5 rounded-[2.5rem] border border-white/5 space-y-6">
                    <div className="flex justify-between items-center">
                      <span className="text-[9px] font-black text-slate-600 tracking-widest uppercase">LEG #{i+1}</span>
                      <button type="button" onClick={() => setFormData(p => ({...(p as any), [type]: (p as any)[type].filter((x: any) => x.id !== f.id)}))} className="text-red-900 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                    </div>
                    <div className="grid grid-cols-2 md:grid-cols-4 gap-4">
                      <div className="col-span-1"><label className={labelClass}>航班号</label><input value={f.flightNo} onChange={e => updateItem(type, f.id, {flightNo: e.target.value})} className={inputClass} placeholder="CX411" /></div>
                      <div className="col-span-1"><label className={labelClass}>单段价格</label><input type="number" value={f.price} onChange={e => updateItem(type, f.id, {price: Number(e.target.value)})} className={inputClass} /></div>
                      <div className="col-span-2"><label className={labelClass}>起/降机场</label>
                        <div className="flex items-center gap-2">
                          <input value={f.depAirport} onChange={e => updateItem(type, f.id, {depAirport: e.target.value})} className={inputClass} placeholder="出发" />
                          <span className="text-white/20">→</span>
                          <input value={f.arrAirport} onChange={e => updateItem(type, f.id, {arrAirport: e.target.value})} className={inputClass} placeholder="到达" />
                        </div>
                      </div>
                    </div>
                    <div className="grid grid-cols-2 gap-4">
                      <div><label className={labelClass}>起飞时间</label><input type="datetime-local" value={f.depTime} onChange={e => updateItem(type, f.id, {depTime: e.target.value})} className={inputClass} /></div>
                      <div><label className={labelClass}>到达时间</label><input type="datetime-local" value={f.arrTime} onChange={e => updateItem(type, f.id, {arrTime: e.target.value})} className={inputClass} /></div>
                    </div>
                  </div>
                ))}
              </React.Fragment>
            ))}
          </div>

          <div className="space-y-6">
            <div className="flex justify-between items-center">
              <SectionHeader title="住宿计划" onAdd={() => setFormData(p => ({...p, hotels: [...p.hotels, {id: crypto.randomUUID(), name:'', checkIn:'', checkOut:'', price:0}]}))} />
              <StatusSwitch active={formData.hotelStatus === 'Booked'} onToggle={() => setFormData(p => ({...p, hotelStatus: p.hotelStatus === 'Booked' ? 'Pending' : 'Booked'}))} />
            </div>
            {formData.hotels.map((h, i) => (
              <div key={h.id} className="p-8 bg-white/5 rounded-[2.5rem] border border-white/5 space-y-6">
                <div className="flex justify-between items-center">
                  <span className="text-[9px] font-black text-slate-600 tracking-widest uppercase">STAY #{i+1}</span>
                  <button type="button" onClick={() => setFormData(p => ({...p, hotels: p.hotels.filter(x => x.id !== h.id)}))} className="text-red-900 hover:text-red-500 transition-colors"><Trash2 className="w-4 h-4" /></button>
                </div>
                <input value={h.name} onChange={e => updateItem('hotels', h.id, {name: e.target.value})} className={inputClass} placeholder="酒店名称及地址..." />
                <div className="grid grid-cols-3 gap-6">
                  <div><label className={labelClass}>入住</label><input type="date" value={h.checkIn} onChange={e => updateItem('hotels', h.id, {checkIn: e.target.value})} className={inputClass} /></div>
                  <div><label className={labelClass}>离店</label><input type="date" value={h.checkOut} onChange={e => updateItem('hotels', h.id, {checkOut: e.target.value})} className={inputClass} /></div>
                  <div><label className={labelClass}>费用</label><input type="number" value={h.price} onChange={e => updateItem('hotels', h.id, {price: Number(e.target.value)})} className={inputClass} /></div>
                </div>
              </div>
            ))}
          </div>

          <div className="space-y-4">
             <label className={labelClass}>备注 / MEMO</label>
             <textarea 
               value={formData.remarks} 
               onChange={e => setFormData({...formData, remarks: e.target.value})} 
               className={`${inputClass} min-h-[120px] resize-none py-4`} 
               placeholder="记录其他重要信息，如接送、攻略等..."
             />
          </div>

          <div className="sticky bottom-0 bg-[#0f172a] pt-10 pb-6 border-t border-white/5 z-50">
            <div className="flex flex-col md:flex-row gap-6 items-center justify-between">
              <div className="flex items-center gap-10">
                 <div className="text-center">
                    <div className="text-[8px] font-black text-slate-600 uppercase mb-1">TOTAL BUDGET</div>
                    <div className="text-4xl font-black text-white italic tracking-tighter">¥{calculateGrandTotal().toLocaleString()}</div>
                 </div>
              </div>
              <div className="flex gap-4 w-full md:w-auto">
                <button type="button" onClick={onClose} className="flex-1 px-10 py-5 border border-white/10 rounded-full font-black text-[10px] tracking-widest text-slate-500 uppercase hover:text-white transition-all">CANCEL</button>
                <button type="submit" className="flex-[2] px-12 py-5 bg-white text-black rounded-full font-black text-[10px] tracking-widest uppercase flex items-center justify-center gap-3 hover:scale-105 active:scale-95 shadow-2xl transition-all">
                  <Save className="w-5 h-5" /> COMMIT DATA
                </button>
              </div>
            </div>
